INSERT INTO questions
  (id, specialty, stem, choices, correct_answer, explanation, telemetry, domain_name, subtopic, difficulty, "references", status, category)
VALUES
('authored-batch-r20-001', 'Trauma, Burns & Critical Events', 'A healthy, muscular 24-year-old man undergoes general anesthesia for arthroscopic shoulder surgery. During emergence and extubation he develops vigorous laryngospasm with marked sternal retractions and stridor before the airway is re-secured with positive-pressure mask ventilation and a small dose of succinylcholine. Within 10 minutes of relieving the obstruction he becomes progressively hypoxemic (SpO2 84% on 100% oxygen), develops pink frothy secretions in the airway, and bilateral diffuse crackles. He is afebrile and normotensive, and a portable chest radiograph shows bilateral perihilar alveolar infiltrates with a normal cardiac silhouette. Which mechanism best explains this patient''s acute hypoxemia?', '[{"text":"Markedly negative intrathoracic pressure from forced inspiration against a closed glottis increasing transcapillary fluid flux","label":"A","correct":true,"rationale":"Correct: vigorous inspiratory effort against the obstructed airway generates large negative intrathoracic pressure that raises venous return and transpulmonary capillary hydrostatic gradients, producing negative-pressure (post-obstructive) pulmonary edema."},{"text":"Aspiration of acidic gastric contents during the obstructive episode","label":"B","correct":false,"rationale":"Aspiration can cause hypoxemia and infiltrates, but it typically produces unilateral or gravity-dependent (often right lower lobe) opacities and lacks the characteristic temporal link to forceful inspiration against a closed glottis."},{"text":"Acute decompensated left ventricular systolic failure from anesthetic-induced cardiomyopathy","label":"C","correct":false,"rationale":"This young healthy patient has no cardiac history and a normal cardiac silhouette, and anesthetics do not acutely produce systolic heart failure of this kind."},{"text":"IgE-mediated anaphylaxis to neuromuscular blocking agents causing capillary leak","label":"D","correct":false,"rationale":"Anaphylaxis would be expected to cause hypotension, bronchospasm, and often cutaneous signs rather than isolated post-obstructive pulmonary edema in a hemodynamically stable patient."},{"text":"Methemoglobinemia from a topical local anesthetic applied to the airway","label":"E","correct":false,"rationale":"Methemoglobinemia causes a saturation gap and chocolate-brown blood with a normal chest film, not bilateral alveolar infiltrates and frothy pulmonary edema."}]'::jsonb, 'A', 'Negative-pressure (post-obstructive) pulmonary edema classically occurs in young, muscular patients who generate large negative intrathoracic pressures by inspiring forcefully against an obstructed airway, most often laryngospasm at extubation. The negative pressure increases venous return and right ventricular preload while raising the transpulmonary hydrostatic gradient, driving fluid into the alveoli; the result is rapid-onset hypoxemia with frothy secretions and bilateral perihilar infiltrates and a normal heart size. Management is supportive with supplemental oxygen, maintenance of a patent airway, and CPAP/PEEP or noninvasive ventilation; it is usually self-limited and resolves within 12 to 48 hours, and aggressive diuresis is rarely needed.', '{}'::jsonb, 'Subspecialty Care', 'Negative-pressure (post-obstructive) pulmonary edema after laryngospasm', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/postobstructive-pulmonary-edema/","source":"Postobstructive Pulmonary Edema - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Trauma, Burns & Critical Events'),
('authored-batch-r20-002', 'Trauma, Burns & Critical Events', 'A 38-year-old semiconductor-plant worker is brought to the OR for debridement after splashing concentrated hydrofluoric acid on both hands and forearms (~6% total body surface area). The skin was copiously irrigated at the scene. He reports severe, deep, throbbing pain out of proportion to the modest-appearing burns. On the monitor you note frequent premature ventricular contractions and a prolonging QT interval, and he complains of perioral and finger tingling. A point-of-care ionized calcium is low. In addition to topical and infiltrative calcium therapy at the burn site, which intervention most directly addresses the life-threatening derangement driving his arrhythmia?', '[{"text":"Administer intravenous sodium bicarbonate to alkalinize and neutralize residual acid","label":"A","correct":false,"rationale":"Systemic bicarbonate does not correct the fluoride-induced electrolyte depletion responsible for the arrhythmia and risks worsening ionized hypocalcemia by increasing calcium binding to albumin."},{"text":"Administer intravenous calcium (and replace magnesium) to correct fluoride-induced hypocalcemia and hypomagnesemia","label":"B","correct":true,"rationale":"Correct: absorbed fluoride avidly chelates calcium and magnesium, producing systemic hypocalcemia/hypomagnesemia with QT prolongation and ventricular dysrhythmias, so intravenous calcium and magnesium repletion is the priority systemic therapy."},{"text":"Give intravenous potassium chloride to treat presumed hypokalemia from acid exposure","label":"C","correct":false,"rationale":"Fluoride toxicity classically causes hyper-, not hypo-, kalemia from cellular efflux, so empiric potassium loading could precipitate dangerous hyperkalemia."},{"text":"Start an insulin-dextrose infusion to shift potassium intracellularly","label":"D","correct":false,"rationale":"Insulin-dextrose treats hyperkalemia but does nothing to replace the depleted calcium and magnesium that are the proximate cause of the QT prolongation and ectopy."},{"text":"Administer intralipid (20% lipid emulsion) as a sink for the absorbed fluoride","label":"E","correct":false,"rationale":"Lipid emulsion rescue is for lipophilic local anesthetic and similar drug toxicity; fluoride is a small water-soluble ion that lipid emulsion cannot sequester."}]'::jsonb, 'B', 'Hydrofluoric acid is a weak acid whose danger lies in the highly reactive fluoride ion, which penetrates tissue and avidly binds calcium and magnesium, producing severe systemic hypocalcemia and hypomagnesemia. The resulting QT prolongation, ventricular ectopy, and risk of fatal arrhythmia can occur even with small-surface-area burns, and pain is characteristically out of proportion to skin findings. Treatment is twofold: local calcium (topical gel, subcutaneous infiltration, or intra-arterial infusion) to bind fluoride in tissue, plus aggressive intravenous calcium and magnesium repletion with continuous ECG monitoring; fluoride can also cause hyperkalemia, which is treated concurrently.', '{}'::jsonb, 'Subspecialty Care', 'Hydrofluoric acid chemical burn with systemic hypocalcemia', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK441829/","source":"Hydrofluoric Acid Burns - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Trauma, Burns & Critical Events'),
('authored-batch-r20-003', 'Trauma, Burns & Critical Events', 'A 29-year-old man is brought to the trauma bay after an enclosed-space industrial explosion. He has no penetrating wounds but reports dyspnea and hemoptysis. Vitals: HR 118, BP 104/70, RR 32, SpO2 88% on a non-rebreather. Exam shows bilateral ruptured tympanic membranes and diffuse crackles; chest radiograph reveals a bilateral ''butterfly'' alveolar infiltrate pattern without rib fractures or pneumothorax. As you prepare him for emergent anesthesia, which statement most accurately guides safe management of his primary blast lung injury?', '[{"text":"Ruptured tympanic membranes reliably exclude significant blast lung injury, so aggressive positive-pressure ventilation is safe","label":"A","correct":false,"rationale":"Tympanic membrane rupture indicates exposure to substantial overpressure but does not exclude or predict the severity of pulmonary injury, and it should heighten, not lower, concern."},{"text":"Large-volume crystalloid resuscitation to a supranormal preload is the priority to optimize oxygen delivery","label":"B","correct":false,"rationale":"Over-resuscitation worsens blast lung edema and oxygenation, so judicious fluid management rather than aggressive volume loading is preferred when hemorrhage is not the dominant problem."},{"text":"Use lung-protective low-tidal-volume ventilation and maintain high vigilance for tension pneumothorax and systemic air embolism","label":"C","correct":true,"rationale":"Correct: primary blast lung injury is managed like ARDS with low-tidal-volume, pressure-limited ventilation, judicious fluids, and constant readiness for pneumothorax and arterial air embolism, which can be precipitated by positive-pressure ventilation."},{"text":"High tidal volumes and high airway pressures should be used to recruit the injured alveoli","label":"D","correct":false,"rationale":"High tidal volumes and pressures increase barotrauma and the risk of alveolar rupture and arterial air embolism in blast-injured lungs and are specifically harmful."},{"text":"Nitrous oxide is the preferred maintenance agent because it reduces opioid requirements","label":"E","correct":false,"rationale":"Nitrous oxide expands gas-filled spaces and is contraindicated given the high risk of occult pneumothorax and air embolism in blast lung."}]'::jsonb, 'C', 'Primary blast injury results from the overpressure wave acting on gas-containing organs; the lung is most vulnerable, producing alveolar hemorrhage and edema (a ''butterfly'' radiographic pattern) that behaves like ARDS. Positive-pressure ventilation is hazardous because alveolar disruption predisposes to tension pneumothorax and to systemic arterial air embolism, so clinicians should use low tidal volumes and limited airway pressures, avoid nitrous oxide, resuscitate fluids judiciously, and decompress the chest promptly if hemodynamics deteriorate. Tympanic membrane rupture signals significant blast exposure but neither confirms nor rules out the severity of pulmonary or other internal injury.', '{}'::jsonb, 'Subspecialty Care', 'Primary blast (blast lung) injury and ventilation strategy', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK430914/","source":"Blast Injuries - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Trauma, Burns & Critical Events'),
('authored-batch-r20-004', 'Thoracic & Vascular', 'A 64-year-old man with COPD undergoes right upper lobectomy via video-assisted thoracoscopy under general anesthesia with a left-sided double-lumen tube. Twenty minutes after the surgeon collapses the right lung and one-lung ventilation begins, the SpO2 drifts from 98% to 84% on FiO2 1.0. Fiberoptic bronchoscopy confirms the tube is correctly positioned and the dependent (left) lung is well aspirated and inflating normally; tidal volume is 6 mL/kg, plateau pressure is 24 cmH2O, and the patient is hemodynamically stable. The surgeon can tolerate a brief pause but does not want the operative lung re-inflated. What is the most appropriate next intervention to improve oxygenation?', '[{"text":"Increase the dependent-lung tidal volume to 10 mL/kg to recruit more alveoli","label":"A","correct":false,"rationale":"Incorrect: large tidal volumes overdistend the dependent lung, raise its pulmonary vascular resistance, and divert blood to the nonventilated lung, worsening shunt and risking lung injury."},{"text":"Decrease FiO2 to 0.6 to limit absorption atelectasis in the dependent lung","label":"B","correct":false,"rationale":"Incorrect: with the patient already hypoxemic at 84%, lowering FiO2 removes the principal oxygen reserve and would deepen desaturation."},{"text":"Administer intravenous nitroglycerin to reduce pulmonary artery pressure","label":"C","correct":false,"rationale":"Incorrect: systemic vasodilators blunt hypoxic pulmonary vasoconstriction in the nonventilated lung, increasing shunt fraction and typically worsening oxygenation during one-lung ventilation."},{"text":"Apply 5-10 cmH2O CPAP with oxygen to the nondependent (operative) right lung","label":"D","correct":true,"rationale":"Correct: with tube position confirmed and the dependent lung optimized, low-level CPAP to the collapsed lung oxygenates blood traversing its persistent shunt and is the next maneuver that does not require full re-inflation."},{"text":"Permanently abandon one-lung ventilation and resume two-lung ventilation for the case","label":"E","correct":false,"rationale":"Incorrect: definitive two-lung ventilation is reserved for refractory or unstable hypoxemia, and the surgeon has explicitly asked to keep the operative lung collapsed, so less disruptive measures should be tried first."}]'::jsonb, 'D', 'Hypoxemia during one-lung ventilation is driven by transpulmonary shunt through the collapsed, nonventilated lung. After confirming correct tube position and optimizing the dependent lung (suctioning, appropriate tidal volume, and PEEP), the next step that improves oxygenation without re-inflating the surgical field is applying low-level CPAP with oxygen to the nondependent lung, which oxygenates the shunted blood. Maneuvers that raise dependent-lung pressures excessively or that blunt hypoxic pulmonary vasoconstriction (e.g., systemic vasodilators) tend to worsen the shunt. Reverting to two-lung ventilation is the rescue option for refractory or hemodynamically significant desaturation.', '{}'::jsonb, 'Subspecialty Care', 'One-lung ventilation: management of intraoperative hypoxemia', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/hypoxia-during-one-lung-ventilation/","source":"Hypoxia During One-Lung Ventilation - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Thoracic & Vascular'),
('authored-batch-r20-005', 'Thoracic & Vascular', 'A 72-year-old man undergoes open repair of an infrarenal abdominal aortic aneurysm. He has well-controlled hypertension and a remote coronary stent placed 4 years ago for stable angina; he is asymptomatic and on aspirin and a statin. An infrarenal aortic cross-clamp is applied. Compared with the hemodynamic response expected from a supraceliac clamp, which statement best describes the physiology of this infrarenal clamp and the patient''s preoperative ASA physical status?', '[{"text":"Preload reliably increases as blood shifts proximally, identical to a supraceliac clamp; the patient is ASA II","label":"A","correct":false,"rationale":"Incorrect: a reliable preload rise requires a supraceliac clamp, and a remote coronary stent classifies him as ASA III rather than ASA II."},{"text":"Preload typically does not rise because the splanchnic bed absorbs the volume; the patient is ASA II","label":"B","correct":false,"rationale":"Incorrect: the preload physiology is right, but a remote coronary stent (CAD) places him at ASA III, not ASA II."},{"text":"Preload reliably increases because all infrarenal clamps redirect splanchnic blood centrally; the patient is ASA III","label":"C","correct":false,"rationale":"Incorrect: the ASA class is correct, but infrarenal clamping characteristically does NOT raise preload because the splanchnic veins sequester the displaced volume."},{"text":"Preload falls sharply from acute afterload reduction; the patient is ASA IV","label":"D","correct":false,"rationale":"Incorrect: cross-clamping raises afterload rather than reducing it, and a remote stable coronary stent without decompensation does not meet ASA IV criteria for a constant threat to life."},{"text":"Preload typically does not rise because the splanchnic venous bed absorbs the displaced volume; the patient is ASA III","label":"E","correct":true,"rationale":"Correct: with the clamp below the splanchnic outflow, blood displaced from below the clamp is accommodated by the compliant splanchnic veins so central preload usually does not increase, and a remote coronary stent makes him ASA III even when asymptomatic."}]'::jsonb, 'E', 'The hemodynamic impact of aortic cross-clamping depends critically on clamp level relative to the splanchnic vasculature. A supraceliac clamp shifts blood from below the clamp into the central circulation and reliably increases preload, whereas an infraceliac/infrarenal clamp allows the compliant splanchnic venous bed to absorb the displaced volume, so preload generally does not rise. For ASA physical status, a remote (greater than 3 months) coronary stent or established CAD is ASA III even when the patient is asymptomatic and optimized; well-controlled hypertension alone would be only ASA II and should not be additively stacked into a higher class.', '{}'::jsonb, 'Subspecialty Care', 'Aortic cross-clamp hemodynamics and ASA physical status in AAA repair', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/aortic-cross-clamping/","source":"Aortic Cross-Clamping - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Thoracic & Vascular'),
('authored-batch-r20-006', 'Thoracic & Vascular', 'A 70-year-old woman undergoes carotid endarterectomy for symptomatic 80% internal carotid stenosis under superficial cervical plexus block with the patient awake for continuous neurologic assessment. Baseline blood pressure is 150/80 mmHg. Moments after the surgeon applies the carotid cross-clamp, the patient becomes confused, develops slurred speech, and cannot squeeze a ball with the contralateral hand; the surgeon has not yet placed a shunt. What is the most appropriate immediate management?', '[{"text":"Pharmacologically raise mean arterial pressure toward and above baseline while the surgeon places a carotid shunt","label":"A","correct":true,"rationale":"Correct: a new deficit on clamping signals inadequate collateral flow through the circle of Willis, and raising MAP augments contralateral perfusion while shunt placement restores antegrade flow."},{"text":"Administer labetalol to lower blood pressure and reduce cerebral metabolic demand","label":"B","correct":false,"rationale":"Incorrect: lowering blood pressure during clamp-induced ischemia further reduces collateral cerebral perfusion pressure and would worsen the deficit."},{"text":"Immediately convert to general anesthesia and intubate to secure the airway","label":"C","correct":false,"rationale":"Incorrect: emergent conversion abolishes the awake neurologic exam and delays the corrective steps of raising pressure and shunting, which directly address the ischemia."},{"text":"Give a 500 mL crystalloid bolus and continue observation without shunting","label":"D","correct":false,"rationale":"Incorrect: a fluid bolus alone neither rapidly augments cerebral perfusion pressure during clamping nor restores antegrade carotid flow, and passive observation risks infarction."},{"text":"Deepen the cervical plexus block with additional local anesthetic to control the patient","label":"E","correct":false,"rationale":"Incorrect: additional local anesthetic does nothing for cerebral ischemia and risks complications such as phrenic nerve block without addressing the deficit."}]'::jsonb, 'A', 'During awake carotid endarterectomy, a new neurologic deficit appearing at cross-clamp application indicates that collateral flow through the circle of Willis is insufficient to perfuse the ipsilateral hemisphere. The immediate response is to raise mean arterial pressure toward or above baseline to drive contralateral collateral flow and to place an intraluminal shunt to restore antegrade perfusion. Lowering blood pressure, deepening the block, or simply observing would deepen ischemia, and emergent conversion to general anesthesia sacrifices the real-time neurologic monitoring that makes the awake technique valuable.', '{}'::jsonb, 'Subspecialty Care', 'Carotid endarterectomy: awake regional anesthesia and cross-clamp neuromonitoring', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/carotid-stenosis/","source":"Carotid Stenosis - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Thoracic & Vascular'),
('authored-batch-r20-007', 'Pharmacology', 'A 4-year-old, 16-kg child undergoes flexible bronchoscopy under sedation for recurrent stridor. The pharynx is anesthetized with a 20% benzocaine topical spray before the procedure. Twenty minutes later the child becomes cyanotic and lethargic. The SpO2 reads 86% and does not improve despite a non-rebreather mask delivering 100% oxygen; an arterial blood gas drawn at the same time shows PaO2 240 mmHg, and the sample is described as chocolate-brown. Heart rate is 150/min, blood pressure is 92/58 mmHg. Which of the following is the most appropriate next pharmacologic intervention?', '[{"text":"Sodium thiosulfate 12.5 g IV with hydroxocobalamin","label":"A","correct":false,"rationale":"Incorrect: this is the cyanide-toxicity regimen, not a treatment for the methemoglobin produced by an oxidizing local anesthetic."},{"text":"Methylene blue 1-2 mg/kg IV over about 5 minutes","label":"B","correct":true,"rationale":"Correct: the chocolate-brown blood, SpO2 fixed near 85% despite a high PaO2, and benzocaine exposure indicate acquired methemoglobinemia, for which methylene blue reduces ferric heme back to the oxygen-binding ferrous state."},{"text":"20% intravenous lipid emulsion bolus over 2-3 minutes","label":"C","correct":false,"rationale":"Incorrect: lipid rescue treats local anesthetic systemic toxicity (cardiac arrest/seizures from amide agents), not the oxidized-hemoglobin state caused by benzocaine."},{"text":"High-dose ascorbic acid (vitamin C) IV as first-line therapy","label":"D","correct":false,"rationale":"Incorrect: ascorbic acid is a slow, second-line option reserved for patients in whom methylene blue is contraindicated, such as known G6PD deficiency."},{"text":"Immediate exchange transfusion","label":"E","correct":false,"rationale":"Incorrect: transfusion is a salvage measure for refractory or severe cases and is not the first-line response when methylene blue is available and not contraindicated."}]'::jsonb, 'B', 'Benzocaine and prilocaine are classic oxidizing agents that convert hemoglobin iron from the ferrous (Fe2+) to the ferric (Fe3+) state, producing methemoglobin that cannot carry oxygen. The hallmark is a saturation gap: pulse oximetry plateaus near 85% and fails to rise with supplemental oxygen, while co-oximetry confirms an elevated methemoglobin fraction and the blood appears chocolate-brown. First-line treatment is methylene blue 1-2 mg/kg IV over roughly 5 minutes, which acts as an electron donor via NADPH methemoglobin reductase; it is avoided in G6PD deficiency, where ascorbic acid is used instead.', '{}'::jsonb, 'Subspecialty Care', 'Local anesthetics - methemoglobinemia from benzocaine/prilocaine', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK537317/","source":"Methemoglobinemia - StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Pharmacology'),
('authored-batch-r20-008', 'Pharmacology', 'A 58-year-old man with hypertension is intubated and mechanically ventilated in the ICU after an exploratory laparotomy. To facilitate sedation and limit opioid use, the team orders dexmedetomidine and the nurse administers a 1 mcg/kg loading dose over 5 minutes. Two minutes into the loading dose his blood pressure rises transiently from 138/80 to 176/98 mmHg, then over the next several minutes falls to 96/54 mmHg with a heart rate of 46/min. Which mechanism best explains the transient hypertension seen during the rapid loading dose?', '[{"text":"Central alpha-2A agonism in the locus coeruleus reducing norepinephrine release","label":"A","correct":false,"rationale":"Incorrect: central alpha-2A agonism produces the sustained sedation, sympatholysis, hypotension, and bradycardia that follow, not the early pressor response."},{"text":"Beta-1 adrenergic agonism increasing myocardial contractility","label":"B","correct":false,"rationale":"Incorrect: dexmedetomidine has no beta-agonist activity, and the accompanying bradycardia argues against beta-1 stimulation."},{"text":"Stimulation of peripheral postsynaptic alpha-2B receptors on vascular smooth muscle causing vasoconstriction","label":"C","correct":true,"rationale":"Correct: a rapid bolus produces a high plasma concentration that activates peripheral alpha-2B receptors on vascular smooth muscle, transiently raising systemic vascular resistance and blood pressure before central sympatholysis predominates."},{"text":"Baroreceptor-mediated reflex vasoconstriction triggered by the bradycardia","label":"D","correct":false,"rationale":"Incorrect: the hypertension precedes and is independent of the later bradycardia, and reflex responses cannot raise pressure while heart rate is falling."},{"text":"Inhibition of presynaptic norepinephrine reuptake raising synaptic catecholamine levels","label":"E","correct":false,"rationale":"Incorrect: dexmedetomidine is an agonist that suppresses norepinephrine release, not a reuptake inhibitor that would increase catecholamine availability."}]'::jsonb, 'C', 'Dexmedetomidine is a highly selective alpha-2 adrenergic agonist whose dominant clinical effect is central sympatholysis at the locus coeruleus, producing sedation, bradycardia, and hypotension. However, at the high transient plasma levels generated by a rapid loading dose it loses some selectivity and stimulates peripheral postsynaptic alpha-2B receptors on vascular smooth muscle, causing a brief rise in systemic vascular resistance and blood pressure. This biphasic pattern, an initial pressor phase followed by sustained hypotension and bradycardia, is minimized by giving the load over at least 10 minutes or omitting the bolus.', '{}'::jsonb, 'Subspecialty Care', 'Alpha-2 adrenergic agonists - dexmedetomidine hemodynamics', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/dexmedetomidine/","source":"Dexmedetomidine - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pharmacology'),
('authored-batch-r20-009', 'Pharmacology', 'A 67-year-old woman is being separated from cardiopulmonary bypass after a mitral valve repair. After protocolized heparin reversal is begun with protamine, she abruptly develops systemic hypotension (BP 70/40 mmHg) while the surgeon notes the right ventricle becoming distended and poorly contractile. The pulmonary artery catheter shows pulmonary artery pressure rising from 28/14 to 62/34 mmHg, with a falling left atrial pressure. There is no rash, urticaria, or bronchospasm. Which of the following best characterizes this protamine reaction and its initial management?', '[{"text":"Type I reaction from rapid administration; simply slow the infusion and give a fluid bolus","label":"A","correct":false,"rationale":"Incorrect: a type I reaction is transient isolated hypotension from rapid injection, not the acute pulmonary hypertension and RV failure described here."},{"text":"Type II anaphylactoid reaction; treat immediately with epinephrine, antihistamines, and corticosteroids","label":"B","correct":false,"rationale":"Incorrect: the absence of urticaria, rash, and bronchospasm argues against an anaphylactoid (type II) mechanism, and the picture is dominated by pulmonary vasoconstriction rather than histamine-mediated features."},{"text":"Heparin rebound; administer an additional dose of protamine","label":"C","correct":false,"rationale":"Incorrect: heparin rebound causes recurrent bleeding from returning anticoagulant effect, not acute pulmonary hypertension, and giving more protamine could worsen this reaction."},{"text":"Type III reaction (catastrophic pulmonary vasoconstriction); stop protamine, support the right ventricle, and be prepared to reheparinize and return to bypass","label":"D","correct":true,"rationale":"Correct: acute pulmonary hypertension with right ventricular failure, systemic hypotension, and low left-heart filling without allergic features is the classic catastrophic type III reaction, managed by halting protamine, supporting the RV, and reheparinizing back onto bypass if needed."},{"text":"Protamine overdose causing its intrinsic anticoagulant effect; reverse with fresh frozen plasma","label":"E","correct":false,"rationale":"Incorrect: protamine''s weak intrinsic anticoagulant effect manifests as bleeding, not pulmonary vasoconstriction with RV failure, and FFP would not address this hemodynamic crisis."}]'::jsonb, 'D', 'Protamine reactions are classified into three types: type I is transient hypotension from rapid injection, type II is an anaphylactic/anaphylactoid response, and type III is catastrophic pulmonary vasoconstriction. The type III reaction is driven by heparin-protamine complexes triggering thromboxane and complement release, producing acute pulmonary hypertension, right ventricular distension and failure, low left-heart filling, and systemic hypotension. Management is to stop the protamine, support the failing right ventricle (inotropes, pulmonary vasodilators such as inhaled nitric oxide or prostacyclin), and be prepared to reheparinize and resume cardiopulmonary bypass or initiate mechanical support.', '{}'::jsonb, 'Subspecialty Care', 'Anticoagulant reversal - protamine reactions', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK547753/","source":"Protamine - StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Pharmacology'),
('authored-batch-r20-010', 'Airway & ENT', 'A 64-year-old man with a T2 glottic squamous cell carcinoma is scheduled for transoral CO2 laser excision of the vocal cord lesion. He has well-controlled hypertension and a 40-pack-year smoking history. The trachea is intubated with a laser-resistant endotracheal tube, the cuff is filled with saline tinted with methylene blue, and the surgeon is about to begin lasing near the cords. The anesthetist is delivering an FiO2 of 0.45 with the remainder nitrous oxide, SpO2 is 100%, and end-tidal sevoflurane is at 1 MAC. Which adjustment most directly reduces the risk of an airway fire before the laser is activated?', '[{"text":"Increase FiO2 to 1.0 to build an oxygen reserve before the apneic portion of the case","label":"A","correct":false,"rationale":"Incorrect: a high FiO2 is the principal oxidizer driving airway fires, and at 100% oxygen a sustained flame ignites almost immediately when the laser strikes the tube or tissue."},{"text":"Deepen the anesthetic by raising end-tidal sevoflurane to 2 MAC","label":"B","correct":false,"rationale":"Incorrect: volatile agent depth governs anesthetic adequacy and hemodynamics, not the combustibility of the airway, and does nothing to lower the oxidizer concentration."},{"text":"Switch from the laser-resistant tube to a standard PVC endotracheal tube for a clearer surgical view","label":"C","correct":false,"rationale":"Incorrect: standard PVC tubes ignite readily and release toxic byproducts such as hydrochloric acid, so reverting to one would substantially raise, not lower, fire risk."},{"text":"Deflate the endotracheal tube cuff to prevent a pressure-related rupture during lasing","label":"D","correct":false,"rationale":"Incorrect: deflating the cuff allows oxygen-enriched gas to leak into the operative field and removes the saline-filled protective barrier, increasing rather than decreasing fire risk."},{"text":"Reduce FiO2 to 0.30 or less and replace the nitrous oxide with air (medical air/nitrogen)","label":"E","correct":true,"rationale":"Correct: both oxygen and nitrous oxide vigorously support combustion, so titrating FiO2 to 0.30 or below and using air as the balance gas minimizes the oxidizer concentration in the surgical field, the single most important fire-prevention step."}]'::jsonb, 'E', 'The fire triad in airway laser surgery is an oxidizer (oxygen and/or nitrous oxide), a fuel (the endotracheal tube and tissue), and an ignition source (the laser). The anesthetist controls the oxidizer: guidelines recommend keeping FiO2 below 0.30 when feasible and eliminating nitrous oxide, since both gases support combustion. Bench data show sustained flames at high FiO2 but no ignition at room-air oxygen concentrations, underscoring that lowering the oxidizer is the most effective preventive measure.', '{}'::jsonb, 'Subspecialty Care', 'Operating room / airway fire safety during laser laryngeal surgery', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/laser-safety/","source":"Anesthesia for Laser Surgery - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Airway & ENT'),
('authored-batch-r20-011', 'Airway & ENT', 'A 5-year-old, 20-kg boy returns to the emergency department 7 hours after an outpatient tonsillectomy with active oral bleeding and several episodes of swallowing and vomiting bright red blood. He is pale and anxious, heart rate 148, blood pressure 88/52, and capillary refill is 3 seconds. He last ate solid food this morning but has been swallowing blood since the bleeding began. Two large-bore IVs are placed and a 20 mL/kg balanced crystalloid bolus is started while blood is sent for type and crossmatch. Regarding induction and airway management for surgical control of the bleeding, which is the most appropriate plan?', '[{"text":"Perform a rapid sequence induction with two functioning suction setups, a styletted tube, and additional laryngoscopes immediately available","label":"A","correct":true,"rationale":"Correct: a bleeding tonsil patient is treated as a full stomach and is hypovolemic, so a rapid sequence induction after volume resuscitation, with redundant suction and backup airway equipment to manage blood obscuring the view, is the standard approach."},{"text":"Perform an inhalational induction by mask, allowing spontaneous ventilation throughout","label":"B","correct":false,"rationale":"Incorrect: this child already has IV access and a stomach full of swallowed blood, so a slow inhalational induction needlessly prolongs the time the airway is unprotected against aspiration."},{"text":"Delay surgery for 6 hours to satisfy standard fasting guidelines before any induction","label":"C","correct":false,"rationale":"Incorrect: ongoing hemorrhage is an emergency that cannot wait for elective fasting intervals, and the patient is already at full-stomach risk regardless of NPO time."},{"text":"Induce with a standard dose of propofol without prior volume resuscitation to speed airway control","label":"D","correct":false,"rationale":"Incorrect: this child is hypovolemic, and a full induction dose of propofol before resuscitation risks profound hypotension and cardiovascular collapse."},{"text":"Place a supraglottic airway device rather than an endotracheal tube to minimize airway stimulation","label":"E","correct":false,"rationale":"Incorrect: a supraglottic airway does not protect against aspiration of blood and gastric contents, which is precisely the hazard in a patient with a bleeding tonsillar fossa."}]'::jsonb, 'A', 'A child with post-tonsillectomy hemorrhage has two superimposed problems: hypovolemia from blood loss and a full stomach from swallowed blood. The patient should be volume-resuscitated before induction, and the airway secured by rapid sequence induction with cricoid pressure (or a controlled variant), an endotracheal tube, and at least two suction devices plus backup laryngoscopes because blood frequently obscures the laryngeal view. Hypoxemia is actually a more common adverse event than aspiration in this population, so preparation for a potentially difficult, blood-filled airway is essential.', '{}'::jsonb, 'Subspecialty Care', 'Post-tonsillectomy hemorrhage: aspiration risk and induction technique', 'easy', '[{"url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC8749229/","source":"Pediatric Anesthesia Management for Post-Tonsillectomy Bleed: Current Status and Future Directions"}]'::jsonb, 'sme_review', 'Airway & ENT'),
('authored-batch-r20-012', 'Airway & ENT', 'A 3-year-old, 15-kg girl is recovering after an adenoidectomy. The trachea is extubated while she is in a light plane of anesthesia. Within seconds she develops paradoxical chest movement, tracheal tug, no audible air movement despite respiratory effort, and an absent capnography trace; SpO2 falls from 99% to 84% and continues to drop. A jaw thrust with continuous positive airway pressure using 100% oxygen and removal of oral secretions does not relieve the obstruction, and the SpO2 is now 72% with the heart rate falling to 70. She has a functioning peripheral IV. What is the most appropriate next intervention?', '[{"text":"Reattempt bag-mask ventilation with higher peak inspiratory pressures and continue suctioning the oropharynx","label":"A","correct":false,"rationale":"Incorrect: complete laryngospasm is glottic closure that does not open with higher mask pressures, and persisting with this approach wastes time while hypoxia and bradycardia worsen."},{"text":"Administer IV succinylcholine to break the laryngospasm, then ventilate with 100% oxygen","label":"B","correct":true,"rationale":"Correct: when CPAP and jaw thrust fail to relieve laryngospasm and the patient is becoming hypoxic and bradycardic, a small dose of succinylcholine (often with atropine for the bradycardia) relaxes the laryngeal muscles and allows ventilation."},{"text":"Perform an immediate emergency surgical cricothyrotomy","label":"C","correct":false,"rationale":"Incorrect: a surgical airway is a last resort reserved for a true cannot-intubate-cannot-oxygenate situation, whereas laryngospasm in a child with IV access is almost always broken pharmacologically first."},{"text":"Give nebulized racemic epinephrine and IV dexamethasone for presumed post-extubation airway edema","label":"D","correct":false,"rationale":"Incorrect: nebulized epinephrine and steroids treat subglottic edema/croup over minutes to hours and do nothing for the acute glottic closure of laryngospasm in this time frame."},{"text":"Reintubate the trachea immediately using direct laryngoscopy without administering any medication","label":"E","correct":false,"rationale":"Incorrect: attempting laryngoscopy against tightly closed, unrelaxed cords is difficult and traumatic, and instrumenting the larynx can deepen the spasm rather than relieve it."}]'::jsonb, 'B', 'Laryngospasm is sustained reflex glottic closure, most common at light planes during induction or emergence and especially after airway surgery in young children. First-line management is removing the stimulus, applying CPAP with 100% oxygen, and a firm jaw thrust (Larson maneuver). When these fail and oxygenation deteriorates with developing bradycardia, succinylcholine is the definitive treatment to relax the laryngeal musculature; atropine is given alongside to treat the hypoxia-related bradycardia, and intramuscular succinylcholine (3-4 mg/kg) is used if no IV is available.', '{}'::jsonb, 'Subspecialty Care', 'Post-extubation laryngospasm: stepwise management', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/laryngospasm/","source":"Laryngospasm - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Airway & ENT'),
('authored-batch-r20-013', 'Endocrine', 'A 47-year-old woman is scheduled for laparoscopic resection of a 5-cm right adrenal mass. She has a 6-month history of episodic pounding headaches, palpitations, and diaphoresis, and plasma free metanephrines are markedly elevated. In clinic her blood pressure is 178/104 mmHg and heart rate is 96 bpm. The surgical team asks the anesthesia care team to begin pharmacologic optimization before surgery. Which of the following is the most appropriate FIRST step in her preoperative preparation?', '[{"text":"Start oral metoprolol to control the heart rate, then add an alpha-blocker once the rate is at goal","label":"A","correct":false,"rationale":"Initiating beta-blockade before adequate alpha-blockade leaves alpha-mediated vasoconstriction unopposed and can precipitate a hypertensive crisis, so this sequence is incorrect."},{"text":"Start a continuous nicardipine infusion and proceed to surgery the same week without oral therapy","label":"B","correct":false,"rationale":"Calcium-channel blockers are useful adjuncts but do not replace several days of oral alpha-blockade and volume repletion, so proceeding immediately is inappropriate."},{"text":"Begin alpha-adrenergic blockade (e.g., phenoxybenzamine or doxazosin) and liberalize salt and fluid intake for 10-14 days","label":"C","correct":true,"rationale":"Alpha-blockade first controls catecholamine-driven vasoconstriction and, with volume expansion, re-fills the contracted intravascular space, making it the correct initial step."},{"text":"Administer intravenous magnesium sulfate as the sole preoperative agent for several days","label":"D","correct":false,"rationale":"Magnesium is a helpful intraoperative adjunct to blunt catecholamine surges but is not a stand-alone outpatient preparation regimen."},{"text":"Withhold all antihypertensives so intraoperative blood pressure lability can guide vasopressor titration","label":"E","correct":false,"rationale":"Leaving the patient unblocked invites catastrophic hypertensive surges on tumor manipulation, so withholding therapy is dangerous and wrong."}]'::jsonb, 'C', 'Catecholamine-secreting tumors require alpha-adrenergic blockade as the first step, started roughly 10-14 days preoperatively along with sodium and fluid loading to re-expand the chronically constricted intravascular volume. Beta-blockade is added only AFTER alpha-blockade is established; giving a beta-blocker first removes beta-2-mediated vasodilation and leaves alpha-mediated vasoconstriction unopposed, which can trigger a hypertensive crisis and acute heart failure. Adequacy of preparation is judged by normalized blood pressure, mild orthostatic hypotension, and resolution of symptoms.', '{}'::jsonb, 'Subspecialty Care', 'Pheochromocytoma resection - preoperative alpha- vs beta-blockade sequencing', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK589634/","source":"Perioperative Management of Pheochromocytoma - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Endocrine'),
('authored-batch-r20-014', 'Endocrine', 'A 58-year-old man with type 2 diabetes (HbA1c 7.2%) presents on postoperative day 1 after an uncomplicated elective right hemicolectomy. He is nauseated, tachypneic with a respiratory rate of 26, and reports malaise. Vitals: HR 104, BP 118/72, SpO2 98% on room air. Fingerstick glucose is 162 mg/dL. Arterial blood gas shows pH 7.21, HCO3 13 mEq/L, anion gap 22, and serum beta-hydroxybutyrate is elevated. His home medications include metformin and empagliflozin, the latter taken until the morning before surgery. Which factor most directly explains this presentation, and what should have been done differently?', '[{"text":"He developed hyperosmolar hyperglycemic state; the metformin should have been continued perioperatively","label":"A","correct":false,"rationale":"HHS produces glucose typically above 600 mg/dL without significant ketoacidosis, which does not match this near-normal glucose with a wide-gap metabolic acidosis and ketonemia."},{"text":"This is lactic acidosis from metformin; the empagliflozin was appropriately stopped and is unrelated","label":"B","correct":false,"rationale":"Metformin-associated lactic acidosis does not produce ketonemia and elevated beta-hydroxybutyrate, so this misattributes the gap to lactate."},{"text":"This is a normal postoperative stress response; no medication change was indicated","label":"C","correct":false,"rationale":"A pH of 7.21 with a wide anion gap and ketonemia is a pathologic ketoacidosis, not a benign stress response."},{"text":"The empagliflozin precipitated euglycemic diabetic ketoacidosis; it should have been held about 3-4 days before surgery","label":"D","correct":true,"rationale":"SGLT2 inhibitors cause ketoacidosis with near-normal glucose via glycosuria and shifted substrate metabolism, and guidelines call for holding them 3-4 days preoperatively, making this correct."},{"text":"He has acute kidney injury causing uremic acidosis; SGLT2 inhibitors prevent this and should be restarted","label":"E","correct":false,"rationale":"Uremic acidosis is driven by retained organic acids with elevated BUN/creatinine, not ketones, and does not fit the clinical picture."}]'::jsonb, 'D', 'SGLT2 inhibitors (empagliflozin, dapagliflozin, canagliflozin) can precipitate euglycemic diabetic ketoacidosis in the perioperative period: persistent glycosuria lowers plasma glucose while fasting, stress, and volume shifts drive lipolysis and ketogenesis, so the patient is acidotic and ketotic despite a near-normal glucose. Because glucose is not strikingly high, the diagnosis is easily missed; any perioperative patient on an SGLT2 inhibitor with unexplained anion-gap acidosis or tachypnea should have ketones checked. Current FDA and society guidance recommends holding these agents roughly 3-4 days before elective surgery, and these drugs can cause prolonged ketonemia even after they are stopped.', '{}'::jsonb, 'Subspecialty Care', 'SGLT2 inhibitors and perioperative euglycemic diabetic ketoacidosis', 'hard', '[{"url":"https://www.apsf.org/article/editorial-euglycemic-ketoacidosis-concerns-in-perioperative-use-of-sglt2-inhibitors-re-examining-current-recommendations/","source":"Editorial: Euglycemic Ketoacidosis Concerns in Perioperative Use of SGLT2 Inhibitors - Anesthesia Patient Safety Foundation"}]'::jsonb, 'sme_review', 'Endocrine'),
('authored-batch-r20-015', 'Endocrine', 'A 34-year-old woman with poorly controlled Graves disease undergoes emergency appendectomy. Two hours postoperatively she becomes agitated and confused, with temperature 40.1 C, HR 156 (atrial fibrillation), and BP 150/60 mmHg. Thyroid storm is diagnosed and the team begins propranolol, propylthiouracil, hydrocortisone, and active cooling. The resident then prepares to give potassium iodide (SSKI) immediately to block hormone release. Regarding the iodide, what is the most appropriate action?', '[{"text":"Give the iodide before the propylthiouracil to halt hormone release as quickly as possible","label":"A","correct":false,"rationale":"Giving iodide before the thionamide can supply substrate for new hormone synthesis and transiently worsen thyrotoxicosis, so this order is wrong."},{"text":"Omit the iodide entirely because it has no role in thyroid storm","label":"B","correct":false,"rationale":"Iodide is a standard component of storm therapy via the Wolff-Chaikoff effect to inhibit hormone release, so omitting it is incorrect."},{"text":"Replace the propylthiouracil with iodide, since both block hormone synthesis by the same mechanism","label":"C","correct":false,"rationale":"Iodide chiefly blocks hormone RELEASE while thionamides block SYNTHESIS, so they are complementary rather than interchangeable."},{"text":"Give iodide only if the propranolol fails to control the heart rate","label":"D","correct":false,"rationale":"Iodide addresses hormone release, not rate control, and its use is not contingent on the response to beta-blockade."},{"text":"Give the iodide at least about 1 hour AFTER the propylthiouracil has been administered","label":"E","correct":true,"rationale":"Administering the thionamide first blocks new hormone synthesis so that the iodide''s substrate load is not converted into additional stored hormone, making delayed iodide the correct approach."}]'::jsonb, 'E', 'In thyroid storm, the thionamide (propylthiouracil or methimazole) is given FIRST to block new thyroid hormone synthesis; iodide is then added about an hour later to inhibit hormone release (Wolff-Chaikoff effect). If iodide is given before the synthesis pathway is blocked, the extra iodine can be organified into newly synthesized hormone and transiently worsen the thyrotoxic state. PTU is often preferred acutely because it also blocks peripheral T4-to-T3 conversion; beta-blockade (propranolol) controls adrenergic symptoms and rate, and glucocorticoids treat relative adrenal insufficiency while also reducing peripheral conversion.', '{}'::jsonb, 'Subspecialty Care', 'Thyroid storm - sequencing of thionamide before iodide', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK448095/","source":"Thyroid Storm - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Endocrine'),
('authored-batch-r20-016', 'Ophthalmic', 'A 64-year-old man with type 2 diabetes (last HbA1c 7.1%) and well-controlled hypertension underwent pars plana vitrectomy 9 days ago for a tractional retinal detachment, during which the surgeon injected a 14% perfluoropropane (C3F8) gas tamponade. He now presents for an urgent open reduction of a fractured ankle and requires general anesthesia. Vitreoretinal records confirm a residual intraocular gas bubble is still present on slit-lamp exam. Which of the following intraoperative anesthetic decisions is MOST critical to preventing a vision-threatening complication?', '[{"text":"Avoid nitrous oxide and maintain anesthesia with an air/oxygen and volatile or total intravenous technique","label":"A","correct":true,"rationale":"Correct: nitrous oxide is far more soluble than the intraocular fluorinated gas, so it diffuses into the bubble faster than the gas leaves, expanding it and raising intraocular pressure enough to compromise central retinal artery perfusion."},{"text":"Avoid succinylcholine because it will rupture the closed globe through extraocular muscle contraction","label":"B","correct":false,"rationale":"Incorrect: the globe is intact and closed after vitrectomy, and the transient intraocular pressure rise from succinylcholine does not threaten a sealed eye the way an unabsorbed expandable gas bubble does."},{"text":"Maintain an end-tidal CO2 of 30 mmHg to reduce choroidal blood volume and shrink the bubble","label":"C","correct":false,"rationale":"Incorrect: modest hypocapnia does not meaningfully alter a fixed-volume intraocular gas bubble and ignores the dominant mechanism of nitrous-oxide-driven expansion."},{"text":"Administer intravenous acetazolamide prophylactically to keep the bubble from enlarging","label":"D","correct":false,"rationale":"Incorrect: acetazolamide lowers aqueous production but cannot offset rapid nitrous oxide influx into the bubble, so it is no substitute for simply withholding nitrous oxide."},{"text":"Position the patient strictly supine to keep the gas bubble away from the optic nerve head","label":"E","correct":false,"rationale":"Incorrect: positioning influences which retinal break the bubble tamponades but does nothing to prevent the gas-volume expansion and pressure spike caused by nitrous oxide."}]'::jsonb, 'A', 'An intraocular gas bubble (SF6 or C3F8) creates a closed, expandable air-filled space. Because nitrous oxide is roughly 20-30 times more soluble in blood than these fluorinated gases, it enters the bubble faster than the gas can leave, increasing bubble volume and intraocular pressure to the point of central retinal artery occlusion and blindness. Nitrous oxide must be avoided while any bubble persists, which is up to several weeks for SF6 and longer for C3F8, so confirmation of a residual bubble mandates a nitrous-free technique.', '{}'::jsonb, 'Subspecialty Care', 'Intraocular gas tamponade and nitrous oxide expansion', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK572131/","source":"Anesthesia for Ophthalmic Surgery (StatPearls)"}]'::jsonb, 'sme_review', 'Ophthalmic'),
('authored-batch-r20-017', 'Ophthalmic', 'A 27-year-old man is brought emergently for repair of an open-globe injury after being struck in the eye by a metal fragment; vitreous is visibly extruding. He ate a full meal 90 minutes ago and is in pain and retching. He has no other comorbidities (ASA II). The anesthesiologist must perform a rapid-sequence induction to secure the airway while minimizing the risk of expelling intraocular contents. Which approach BEST balances aspiration risk against the goal of avoiding a rise in intraocular pressure?', '[{"text":"Inhalational induction with sevoflurane and spontaneous ventilation, deferring any neuromuscular blocker","label":"A","correct":false,"rationale":"Incorrect: a slow inhalational induction in a full-stomach patient who is actively retching maximizes aspiration risk and does not reliably blunt the intraocular pressure rise from coughing or laryngoscopy."},{"text":"A modified rapid-sequence induction using high-dose rocuronium with adequate intravenous induction agent and opioid to blunt the laryngoscopy response","label":"B","correct":true,"rationale":"Correct: a non-depolarizing relaxant such as high-dose rocuronium provides rapid intubating conditions without the intraocular pressure rise associated with succinylcholine, while a deep induction with opioid blunts the pressor and IOP response to laryngoscopy in this full-stomach patient."},{"text":"Awake fiberoptic intubation with topical airway anesthesia and minimal sedation","label":"C","correct":false,"rationale":"Incorrect: an awake, coughing, straining patient generates large intraocular pressure spikes (and the Valsalva of gagging) that directly threaten extrusion of globe contents."},{"text":"Rapid-sequence induction with succinylcholine because controlling the airway quickly outweighs any theoretical intraocular pressure concern","label":"D","correct":false,"rationale":"Incorrect: succinylcholine transiently raises intraocular pressure through tonic extraocular muscle contraction, which is the one preventable IOP rise to avoid in an open globe when an equally fast non-depolarizer is available."},{"text":"Induce with ketamine alone to preserve airway reflexes and spontaneous breathing without a relaxant","label":"E","correct":false,"rationale":"Incorrect: relying on preserved airway reflexes means the patient may cough and strain, and ketamine without neuromuscular blockade provides poor intubating conditions in a struggling full-stomach trauma patient."}]'::jsonb, 'B', 'In open-globe injury the anesthetic must reconcile two competing imperatives: protecting against aspiration in a usually full-stomach trauma patient and preventing any rise in intraocular pressure that could extrude vitreous or other contents. A modified rapid-sequence induction with a deep induction dose, an opioid to blunt the laryngoscopy pressor response, and a high-dose non-depolarizing relaxant (rocuronium) delivers fast intubating conditions without the IOP rise classically attributed to succinylcholine. Avoiding coughing, straining, and external pressure on the globe is the unifying principle.', '{}'::jsonb, 'Subspecialty Care', 'Open-globe injury: airway management and intraocular pressure', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK551637/","source":"Globe Rupture (StatPearls)"}]'::jsonb, 'sme_review', 'Ophthalmic'),
('authored-batch-r20-018', 'Ophthalmic', 'A 72-year-old woman with mild, well-controlled hypertension is scheduled for elective cataract extraction under monitored anesthesia care. The ophthalmologist places a retrobulbar block after light sedation. Shortly after the block injection, the patient becomes confused, then apneic with a fixed dilated contralateral pupil, and her blood pressure and heart rate fall. Which complication of the block is the MOST likely explanation for this constellation of findings?', '[{"text":"Retrobulbar hemorrhage causing acute orbital compartment syndrome","label":"A","correct":false,"rationale":"Incorrect: retrobulbar hemorrhage produces a tense, proptotic eye with rising intraocular pressure rather than sudden apnea, altered consciousness, and contralateral pupillary signs."},{"text":"Oculocardiac reflex triggered by needle-induced traction on the extraocular muscles","label":"B","correct":false,"rationale":"Incorrect: the oculocardiac reflex causes bradycardia and occasionally asystole but does not by itself cause apnea, confusion, or a fixed contralateral pupil."},{"text":"Brainstem anesthesia from inadvertent injection of local anesthetic into the optic nerve sheath with spread to the subarachnoid space","label":"C","correct":true,"rationale":"Correct: local anesthetic tracking along the optic nerve dural sheath into the CSF spreads to the brainstem, producing apnea, altered mental status, cardiovascular instability, and contralateral cranial nerve signs within minutes of the block."},{"text":"Globe perforation by the block needle","label":"D","correct":false,"rationale":"Incorrect: globe perforation causes pain, sudden loss of vision, and vitreous hemorrhage localized to the eye, not the central nervous system signs of apnea and altered consciousness."},{"text":"Systemic local anesthetic toxicity from intravascular absorption of the block dose","label":"E","correct":false,"rationale":"Incorrect: while local anesthetic systemic toxicity can cause CNS and cardiac effects, the small ophthalmic block volume and the hallmark contralateral pupillary involvement point specifically to subarachnoid brainstem spread rather than systemic absorption."}]'::jsonb, 'C', 'Brainstem anesthesia is a recognized complication of retrobulbar and deep peribulbar blocks: the needle penetrates the optic nerve dural sheath and deposits local anesthetic that tracks into the subarachnoid space and reaches the brainstem. The classic picture is the onset, within minutes, of confusion progressing to apnea, hemodynamic instability, and crossed cranial nerve findings such as a contralateral dilated pupil. Management is supportive — secure the airway, ventilate, and support the circulation until the local anesthetic redistributes, with full recovery expected once it does.', '{}'::jsonb, 'Subspecialty Care', 'Regional ophthalmic block complications: brainstem anesthesia', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/regional-anesthesia-for-ophthalmic-surgery/","source":"Regional Anesthesia for Ophthalmic Surgery (OpenAnesthesia)"}]'::jsonb, 'sme_review', 'Ophthalmic'),
('authored-batch-r20-019', 'Pediatric', 'A 4-year-old, 16-kg boy returns to the emergency department 6 hours after outpatient adenotonsillectomy with active oral bleeding and several episodes of swallowing and spitting up dark blood. He last ate a popsicle 90 minutes ago. He is pale and anxious; heart rate 158/min, blood pressure 84/52 mmHg, SpO2 97% on room air, and capillary refill is 3 seconds. Two attempts at peripheral IV access have failed. The surgeon wants to return to the operating room emergently for control of the bleeding tonsillar fossa. After establishing IV access and giving a 20 mL/kg balanced crystalloid bolus, which induction and airway strategy is most appropriate?', '[{"text":"Inhalational induction with sevoflurane, maintain spontaneous ventilation, and intubate deep without neuromuscular blockade","label":"A","correct":false,"rationale":"A slow inhalational induction in a hypovolemic, full-stomach patient invites aspiration of swallowed blood and profound hypotension, making it the least safe approach."},{"text":"Awake fiberoptic intubation after topicalization to avoid hemodynamic instability","label":"B","correct":false,"rationale":"Awake fiberoptic intubation is impractical in a frightened 4-year-old and the fiberoptic view is rapidly obscured by active bleeding, so it is not appropriate here."},{"text":"Standard-dose propofol induction with rocuronium and routine laryngoscopy, deferring gastric decompression until after intubation","label":"C","correct":false,"rationale":"A full induction dose of propofol can precipitate severe hypotension in a hypovolemic child, and routine (non-rapid-sequence) laryngoscopy ignores the aspiration risk."},{"text":"Rapid sequence induction with a reduced dose of induction agent plus succinylcholine, suction immediately available, and a styletted tube one size smaller than usual","label":"D","correct":true,"rationale":"Correct: the bleeding tonsil patient is treated as a full stomach with a likely difficult, blood-obscured view, so RSI with a reduced induction dose (to limit hypotension), rapid-onset paralysis, ready suction, and a smaller styletted tube is the standard of care."},{"text":"Ketamine sedation with a nasopharyngeal airway and spontaneous ventilation while the surgeon cauterizes","label":"E","correct":false,"rationale":"Sedation without a secured airway leaves the trachea unprotected against ongoing blood aspiration and is unacceptable for an actively bleeding tonsil."}]'::jsonb, 'D', 'A post-tonsillectomy hemorrhage is a true anesthetic emergency: the child is hypovolemic and anemic from both visible and swallowed blood, has a stomach full of blood regardless of NPO status, and presents an airway whose view is obscured by ongoing bleeding. Resuscitate with isotonic fluid (and blood as needed) first, then perform a rapid sequence induction with a reduced dose of induction agent to limit hemodynamic collapse, succinylcholine or rocuronium for rapid paralysis, two working suctions, and a styletted endotracheal tube a half-to-full size smaller than predicted. Avoid the temptation of a slow spontaneous-ventilation inhalational induction, which prolongs the period of an unprotected airway in a full-stomach patient.', '{}'::jsonb, 'Subspecialty Care', 'Post-tonsillectomy hemorrhage — emergency airway and resuscitation', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/posttonsillectomy-hemorrhage/","source":"Posttonsillectomy Hemorrhage — OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pediatric'),
('authored-batch-r20-020', 'Pediatric', 'A 3-month-old boy presents for elective bilateral inguinal hernia repair at a hospital-based surgical unit. He was born at 30 weeks gestation and is now 43 weeks postconceptual age. He was discharged from the NICU 3 weeks ago, takes no medications, and his mother reports no recent apnea spells at home. Preoperative hematocrit is 27%. The surgeon and anesthesia team are deciding between general endotracheal anesthesia and a spinal anesthetic. Which statement most accurately guides perioperative planning for this infant?', '[{"text":"Because he is asymptomatic at home, the case can proceed as a routine outpatient discharge after standard PACU recovery","label":"A","correct":false,"rationale":"His young postconceptual age plus anemia place him at meaningful risk for postoperative apnea, so same-day discharge is unsafe regardless of how well he appears at home."},{"text":"A pure spinal anesthetic supplemented with intravenous midazolam sedation eliminates the risk of postoperative apnea","label":"B","correct":false,"rationale":"Adding any sedative such as midazolam to a spinal abolishes the apnea-sparing advantage of regional technique, so this combination does not eliminate the risk."},{"text":"His apnea risk is negligible because he is already past 40 weeks postconceptual age","label":"C","correct":false,"rationale":"The risk does not fall below roughly 1% until about 54-56 weeks PCA, so 43 weeks PCA is still well within the high-risk window."},{"text":"Correcting his anemia is unnecessary because hematocrit has no relationship to apnea in former preterm infants","label":"D","correct":false,"rationale":"Anemia, particularly a hematocrit below 30%, is a well-established independent risk factor for postoperative apnea and warrants attention."},{"text":"He should be admitted for at least 12 hours of postoperative apnea and cardiorespiratory monitoring, and his hematocrit of 27% independently raises that risk","label":"E","correct":true,"rationale":"Correct: at 43 weeks PCA he is below the threshold where apnea risk becomes negligible, anemia (Hct <30%) is an independent risk factor, and current guidance is continuous monitoring for at least 12 hours postoperatively."}]'::jsonb, 'E', 'Former preterm infants are at risk for postoperative apnea, and risk is driven chiefly by low postconceptual age and anemia. The probability of apnea does not fall below about 5% until roughly 48-50 weeks PCA and below 1% until about 54-56 weeks PCA; a hematocrit under 30% is an independent risk factor. A pure spinal anesthetic can reduce apnea risk only if no sedatives or opioids are added — supplementing with midazolam or ketamine eliminates that benefit. Any at-risk infant should be admitted for continuous cardiorespiratory and apnea monitoring for at least 12 hours postoperatively rather than discharged the same day.', '{}'::jsonb, 'Subspecialty Care', 'Apnea of prematurity / postoperative apnea risk in the ex-premature infant', 'medium', '[{"url":"https://www.openanesthesia.org/postoperative_apnea_post_conceptual_age/","source":"Apnea of Prematurity and Postoperative Apnea — OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pediatric'),
('authored-batch-r20-021', 'Pediatric', 'A healthy 5-year-old, 20-kg girl is undergoing examination under anesthesia via a natural-airway sevoflurane technique with a peripheral IV in place. As the surgeon manipulates the airway, she develops inspiratory stridor that progresses to complete absence of breath sounds, paradoxical chest-abdominal movement, and an SpO2 that falls from 99% to 84%. There is no capnograph trace and the bag does not move with attempted positive-pressure ventilation. You stop the stimulus and apply 100% oxygen with continuous positive airway pressure and a vigorous jaw thrust, but the obstruction persists and SpO2 continues to fall to 78%. What is the most appropriate next step?', '[{"text":"Deepen anesthesia with a bolus of intravenous propofol (about 0.5-1 mg/kg) and, if the spasm persists, give intravenous succinylcholine","label":"A","correct":true,"rationale":"Correct: when CPAP and jaw thrust fail, deepening with a small propofol bolus relaxes the cords in many cases, and succinylcholine is the definitive treatment for laryngospasm that does not break."},{"text":"Administer intravenous atropine 0.02 mg/kg and continue CPAP while waiting for the spasm to break","label":"B","correct":false,"rationale":"Atropine treats reflex bradycardia but does nothing to relieve the glottic closure itself, so it is not the next step for persistent desaturating laryngospasm."},{"text":"Immediately attempt direct laryngoscopy and intubation without any additional medication","label":"C","correct":false,"rationale":"Forcing a laryngoscope past tightly adducted cords in a light, spasming child can worsen the spasm and cause airway trauma, so pharmacologic treatment should come first."},{"text":"Perform an emergency surgical cricothyrotomy","label":"D","correct":false,"rationale":"A surgical airway is a last resort for a true ''cannot intubate, cannot oxygenate'' situation and is premature before succinylcholine has been given for reversible laryngospasm."},{"text":"Switch to ketamine to maintain spontaneous ventilation and lighten the anesthetic","label":"E","correct":false,"rationale":"Lightening the plane during active laryngospasm tends to worsen, not relieve, the reflex glottic closure."}]'::jsonb, 'A', 'Laryngospasm is an exaggerated, sustained glottic closure reflex that can rapidly cause hypoxia, bradycardia, and arrest in children. First-line management is to remove the stimulus, apply 100% oxygen with CPAP, and perform a firm jaw thrust (including pressure at the ''laryngospasm notch''). When these maneuvers fail and the child is desaturating, deepen anesthesia with a small propofol bolus; if the spasm still does not break, give succinylcholine (about 0.5-2 mg/kg IV, or roughly 4 mg/kg IM with atropine if no IV access) as the definitive treatment, with atropine for accompanying bradycardia.', '{}'::jsonb, 'Subspecialty Care', 'Pediatric laryngospasm — recognition and stepwise treatment', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/laryngospasm/","source":"Laryngospasm — OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pediatric'),
('authored-batch-r20-022', 'Principles & Preop', 'A 71-year-old man is scheduled for elective open repair of a 5.8-cm infrarenal abdominal aortic aneurysm. He has hypertension controlled on lisinopril, type 2 diabetes on metformin, and former 30-pack-year tobacco use, now quit. He had a drug-eluting coronary stent placed 4 years ago and has had no angina since; he is maintained on aspirin. He reports that he stopped exercising ''because of my knees'' and becomes short of breath after climbing one flight of stairs but cannot say whether he could climb two. His resting ECG shows old Q waves in the inferior leads. Vitals and basic labs are unremarkable. According to current ACC/AHA perioperative guidance, which single feature of this patient most strongly justifies obtaining further cardiac testing (e.g., pharmacologic stress imaging) before proceeding?', '[{"text":"His coronary stent was placed 4 years ago, which mandates stress testing before any noncardiac surgery","label":"A","correct":false,"rationale":"Incorrect: a remote, asymptomatic stent does not by itself mandate stress testing; its timing matters for antiplatelet decisions, not as an automatic indication for ischemia testing."},{"text":"His estimated functional capacity is less than 4 METs and cannot be reliably established in the setting of an elevated-risk vascular procedure","label":"B","correct":true,"rationale":"Correct: inability to achieve 4 METs (cannot climb two flights / walk up a hill) combined with an elevated-risk surgery is the guideline trigger for considering further testing when it would change management."},{"text":"His well-controlled hypertension on lisinopril independently elevates his risk enough to warrant imaging","label":"C","correct":false,"rationale":"Incorrect: well-controlled hypertension is a minor clinical factor and does not on its own justify further cardiac testing."},{"text":"The inferior Q waves on resting ECG confirm active ischemia requiring testing","label":"D","correct":false,"rationale":"Incorrect: old Q waves indicate a prior infarct, not active ischemia, and a resting ECG abnormality alone is not the decisive indication for stress imaging."},{"text":"His former tobacco use places him in a category that always requires preoperative cardiac stress testing","label":"E","correct":false,"rationale":"Incorrect: a remote smoking history is a risk factor but does not categorically mandate cardiac stress testing before surgery."}]'::jsonb, 'B', 'ACC/AHA perioperative algorithms use functional capacity as a pivotal branch point: a patient who can reliably achieve 4 or more METs generally proceeds without further cardiac testing regardless of an elevated-risk procedure, whereas one with poor (<4 METs) or indeterminate capacity facing elevated-risk surgery is the patient in whom stress testing may be considered if the result would change management. This man''s inability to climb two flights of stairs, coupled with an inability to estimate higher exertion, makes his functional capacity the most actionable risk feature. His remote stent and prior MI raise his baseline risk (and make him ASA III) but are not, by themselves, the trigger for additional ischemia testing.', '{}'::jsonb, 'Subspecialty Care', 'Functional capacity (METs) in preoperative cardiac risk assessment', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/preoperative-cardiac-risk-stratification-and-evaluation/","source":"Preoperative Cardiac Risk Stratification and Evaluation - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Principles & Preop'),
('authored-batch-r20-023', 'Principles & Preop', 'During a preoperative airway assessment for an elective thyroidectomy, a 54-year-old woman is asked to sit upright, open her mouth maximally, and protrude her tongue without phonating. The examiner can visualize the soft palate, the fauces, and the uvula, but the faucial (tonsillar) pillars are hidden behind the tongue. Her thyromental distance is 7 cm, mouth opening is 4 cm, and neck extension is full. Which modified Mallampati class does this oropharyngeal view represent, and what is its correct interpretation?', '[{"text":"Class III, indicating a potentially difficult laryngoscopy that mandates an awake fiberoptic approach","label":"A","correct":false,"rationale":"Incorrect: Class III is when only the soft palate and base of the uvula are seen, and no single class mandates a specific airway technique on its own."},{"text":"Class I, which by itself reliably rules out difficult intubation","label":"B","correct":false,"rationale":"Incorrect: Class I additionally shows the faucial pillars, and even a Class I view does not by itself rule out a difficult airway."},{"text":"Class II, generally reassuring, though no single test reliably excludes a difficult airway","label":"C","correct":true,"rationale":"Correct: visibility of the soft palate, fauces, and uvula with the faucial pillars hidden defines modified Mallampati Class II, a generally favorable view that must still be combined with other predictors."},{"text":"Class IV, which by itself confirms a difficult airway regardless of other findings","label":"D","correct":false,"rationale":"Incorrect: Class IV is when only the hard palate is visible, and no single class confirms a difficult airway in isolation."},{"text":"The classification is invalid because the patient should have been asked to phonate during the examination","label":"E","correct":false,"rationale":"Incorrect: the modified Mallampati test is performed without phonation, so the examination as described is valid."}]'::jsonb, 'C', 'In the modified Mallampati classification (assessed seated, mouth maximally open, tongue protruded, without phonation): Class I sees the soft palate, fauces, uvula, and pillars; Class II sees the soft palate, fauces, and uvula; Class III sees the soft palate and only the base of the uvula; and Class IV sees only the hard palate. Visualizing the soft palate, fauces, and uvula while the faucial pillars are hidden is the classic Class II view. Importantly, the Mallampati score has modest sensitivity and specificity, so it should be integrated with thyromental distance, mouth opening, neck mobility, and the 3-3-2 rule rather than used in isolation.', '{}'::jsonb, 'Subspecialty Care', 'Airway assessment and difficult-airway prediction', 'easy', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK585119/","source":"Mallampati Score - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Principles & Preop'),
('authored-batch-r20-024', 'Neuro', 'A 54-year-old man undergoes a suboccipital craniotomy in the sitting position for resection of a vestibular schwannoma. He is monitored with a precordial Doppler over the right parasternal border, an arterial line, and capnography. Roughly 90 minutes into the dissection, the anesthetist hears a sudden change in the Doppler tones to a harsh, churning, "mill-wheel" quality. Over the next 60 seconds the end-tidal CO2 falls from 34 to 21 mmHg, the blood pressure drops to 78/44 mmHg, and the SpO2 begins to decline. The patient is receiving an oxygen/air/sevoflurane mixture. In addition to alerting the surgeon to flood the field with saline and apply bone wax, which intervention is the MOST appropriate IMMEDIATE next step?', '[{"text":"Increase the inspired sevoflurane concentration to deepen anesthesia and blunt the sympathetic response","label":"A","correct":false,"rationale":"Deepening a volatile anesthetic worsens vasodilation and myocardial depression in an already hypotensive patient and does nothing to address entrained air, so it is harmful here."},{"text":"Apply 10 cm H2O of PEEP to raise intrathoracic pressure and tamponade the venous sinuses","label":"B","correct":false,"rationale":"PEEP is unreliable for preventing air entrainment and can paradoxically promote paradoxical embolism by raising right-atrial pressure above left, so it is not the immediate maneuver of choice."},{"text":"Give a 1 mg/kg bolus of intravenous lidocaine to suppress the ventricular ectopy of air embolism","label":"C","correct":false,"rationale":"Lidocaine treats arrhythmias but does nothing to remove the air or support the failing right heart, and ectopy is not the proximate threat in this scenario."},{"text":"Administer 100% oxygen and attempt to aspirate air from the right-atrial central venous catheter","label":"D","correct":true,"rationale":"Switching to 100% oxygen maximizes oxygenation while eliminating any potential for diffusion-mediated bubble expansion, and aspirating from a correctly positioned right-atrial catheter can directly remove entrained air, making this the correct immediate priority."},{"text":"Place the patient immediately in the Trendelenburg, right-lateral decubitus (Durant) position before any other action","label":"E","correct":false,"rationale":"The Durant position is a classic adjunct but is impractical and slow to achieve in a pinned, sitting craniotomy patient and should not precede giving 100% oxygen and aspirating the catheter."}]'::jsonb, 'D', 'A sudden mill-wheel murmur on precordial Doppler with an abrupt drop in end-tidal CO2 and hypotension is the classic presentation of venous air embolism (VAE), a hallmark risk of sitting-position posterior fossa surgery because the non-collapsible dural venous sinuses sit above the heart. The end-tidal CO2 falls because entrained air increases alveolar dead space and impairs ventilation-perfusion matching. Immediate management is to stop further entrainment (flood the field, wax bone edges, lower the head if feasible), switch to 100% oxygen, discontinue any nitrous oxide, and aspirate air from a right-atrial catheter while providing hemodynamic support. Adjuncts such as the Durant position are secondary and often impractical in a pinned patient.', '{}'::jsonb, 'Subspecialty Care', 'Venous air embolism and sitting-position neurosurgery monitoring', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/venous-air-embolism/","source":"Venous Air Embolism - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Neuro'),
('authored-batch-r20-025', 'Neuro', 'A 27-year-old man is brought to the operating room 9 days after a T6 spinal cord transection sustained in a motorcycle collision, now scheduled for urgent debridement and flap coverage of a sacral pressure injury complicated by sepsis. He has flaccid paraplegia below the level of injury. He is hypotensive and tachycardic, and the trauma surgeon requests a rapid-sequence induction because of a full stomach. The resident proposes succinylcholine 1.5 mg/kg to optimize intubating conditions. Which statement BEST describes the principal hazard of this plan?', '[{"text":"Succinylcholine will be ineffective because denervated muscle below the injury is resistant to depolarizing blockade","label":"A","correct":false,"rationale":"Denervated muscle is not resistant to succinylcholine; the problem is an exaggerated pharmacologic response, not failure of relaxation, so this misstates the risk."},{"text":"Succinylcholine will trigger malignant hyperthermia because spinal cord injury upregulates the ryanodine receptor","label":"B","correct":false,"rationale":"Spinal cord injury does not cause malignant-hyperthermia susceptibility, which is a genetic ryanodine-receptor channelopathy unrelated to denervation, so this is incorrect."},{"text":"Succinylcholine will cause a prolonged block because plasma cholinesterase activity is depleted after spinal cord injury","label":"C","correct":false,"rationale":"Pseudocholinesterase activity is not characteristically depleted by spinal cord injury, and prolonged block is not the feared catastrophic event in this setting."},{"text":"Succinylcholine is safe at this interval because receptor upregulation does not begin until roughly 6 months after injury","label":"D","correct":false,"rationale":"This is factually wrong: upregulation of extrajunctional acetylcholine receptors begins within a few days and is well established by the end of the first week, making this interval high-risk."},{"text":"Succinylcholine can precipitate life-threatening hyperkalemia and cardiac arrest from massive efflux through upregulated extrajunctional acetylcholine receptors","label":"E","correct":true,"rationale":"Within days of a denervating spinal cord injury, extrajunctional and immature (fetal-type) acetylcholine receptors proliferate, so depolarization releases a massive potassium load that can cause arrhythmia and cardiac arrest, which is the correct and most feared hazard."}]'::jsonb, 'E', 'After upper motor neuron injuries such as spinal cord transection, skeletal muscle proliferates extrajunctional and immature acetylcholine receptors. When succinylcholine depolarizes these widespread receptors, a large efflux of intracellular potassium can produce acute hyperkalemia, ventricular dysrhythmias, and cardiac arrest. The dangerous window opens within a few days of injury (receptor upregulation is established by roughly the end of the first week) and can persist for many months, so succinylcholine should be avoided well before and long after this 9-day mark. A nondepolarizing agent such as rocuronium is the appropriate choice for rapid-sequence induction in this patient.', '{}'::jsonb, 'Subspecialty Care', 'Succinylcholine-induced hyperkalemia after denervating spinal cord injury', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499984/","source":"Succinylcholine Chloride - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Neuro'),
('authored-batch-r20-026', 'Neuro', 'A 41-year-old woman recovers in the PACU after endoscopic transsphenoidal resection of a pituitary macroadenoma with suprasellar extension. Over the first 6 hours postoperatively she produces 350-450 mL/hr of clear, dilute urine. Her measurements show serum sodium 149 mEq/L (preoperatively 140), serum osmolality 304 mOsm/kg, and urine osmolality 110 mOsm/kg. She is awake and reports intense thirst but is otherwise hemodynamically stable. Which is the MOST appropriate next step in management?', '[{"text":"Replace ongoing free-water losses and administer desmopressin (DDAVP)","label":"A","correct":true,"rationale":"Hypotonic polyuria with a rising serum sodium, high serum osmolality, and inappropriately dilute urine after pituitary surgery is central diabetes insipidus, which is correctly treated by replacing free water and giving the ADH analogue desmopressin."},{"text":"Restrict free water and begin a hypertonic (3%) saline infusion to correct the sodium","label":"B","correct":false,"rationale":"This describes the management of SIADH-associated hyponatremia, the opposite electrolyte derangement, and would dangerously worsen this patient''s hypernatremia and free-water deficit."},{"text":"Administer a 20 mEq potassium chloride bolus and continue observation, attributing the polyuria to intraoperative fluid mobilization","label":"C","correct":false,"rationale":"The picture is dilute polyuria with rising sodium and high serum osmolality, not a potassium problem, and mislabeling true diabetes insipidus as benign diuresis risks progressive hypernatremia."},{"text":"Start a furosemide infusion to manage the high urine output and prevent volume overload","label":"D","correct":false,"rationale":"A loop diuretic would aggravate the already large free-water and volume losses of diabetes insipidus and worsen hypernatremia, making it exactly the wrong intervention."},{"text":"Obtain an urgent CT head to evaluate for cerebral salt wasting before initiating any therapy","label":"E","correct":false,"rationale":"Cerebral salt wasting causes hyponatremia with true volume depletion, not hypernatremia with dilute urine, so this misidentifies the syndrome and delays appropriate desmopressin therapy."}]'::jsonb, 'A', 'Manipulation of the posterior pituitary stalk during transsphenoidal surgery commonly produces transient central diabetes insipidus, especially with macroadenomas that have suprasellar extension. The diagnostic triad is hypotonic polyuria (often greater than 300 mL/hr of dilute urine), a rising serum sodium with elevated serum osmolality, and inappropriately low urine osmolality. Treatment is to replace the free-water deficit and ongoing losses and to administer desmopressin (DDAVP), a selective V2 agonist, while monitoring electrolytes closely to avoid overcorrection and iatrogenic SIADH-type hyponatremia. The condition is usually self-limited but must be distinguished from cerebral salt wasting and SIADH, which present with hyponatremia.', '{}'::jsonb, 'Subspecialty Care', 'Central diabetes insipidus after transsphenoidal pituitary surgery', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK554582/","source":"Desmopressin - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Neuro'),
('authored-batch-r20-027', 'Obstetric', 'A 27-year-old G1P0 at 40 weeks (BMI 29) requests labor analgesia at 5 cm dilation. She is contracting on an oxytocin infusion. A combined spinal-epidural (CSE) is placed with intrathecal fentanyl 25 mcg plus bupivacaine 2.5 mg, and she reports near-complete pain relief within 3 minutes. Maternal blood pressure is 118/72 mmHg (baseline 120/74) and she is positioned with left uterine displacement. Approximately 5 minutes after the intrathecal dose, the fetal heart tracing shows a prolonged deceleration to 70/min, and the tocodynamometer reveals uterine tachysystole with elevated baseline tone. Which mechanism best explains this fetal heart rate change, and what is the most appropriate immediate intervention?', '[{"text":"Maternal hypotension from sympathetic blockade has reduced uteroplacental perfusion; treat with a 500 mL fluid bolus and IV phenylephrine","label":"A","correct":false,"rationale":"Incorrect: her blood pressure is essentially at baseline with no hypotension, so vasopressor-treated hypotension is not the operative mechanism for this bradycardia."},{"text":"An abrupt fall in maternal epinephrine from rapid analgesia has removed tocolytic tone, causing uterine tachysystole and reduced placental perfusion; stop the oxytocin and consider a tocolytic such as terbutaline or nitroglycerin","label":"B","correct":true,"rationale":"Correct: rapid pain relief (especially with the intrathecal opioid of a CSE) sharply lowers circulating epinephrine, whose beta-2 tocolytic effect is lost, producing uterine hypertonus/tachysystole and transient fetal bradycardia best managed by discontinuing oxytocin and uterine relaxation."},{"text":"Direct fetal myocardial depression from systemic absorption of intrathecal fentanyl; administer naloxone to the mother","label":"C","correct":false,"rationale":"Incorrect: the minute intrathecal fentanyl dose produces negligible fetal systemic levels and does not cause fetal bradycardia, so maternal naloxone is not indicated."},{"text":"An unrecognized high spinal has caused maternal bradycardia transmitted to the fetus; give atropine and prepare for intubation","label":"D","correct":false,"rationale":"Incorrect: a high spinal would produce maternal hypotension, bradycardia, and respiratory compromise, none of which are present, and fetal heart rate is not simply a reflection of maternal rate."},{"text":"Aortocaval compression from supine positioning has reduced venous return; reposition the patient fully supine to improve cardiac output","label":"E","correct":false,"rationale":"Incorrect: she is already in left uterine displacement, and placing a term parturient supine would worsen aortocaval compression rather than help."}]'::jsonb, 'B', 'Fetal bradycardia after neuraxial labor analgesia, more common with CSE than epidural alone, is classically caused by uterine tachysystole rather than maternal hypotension. The abrupt analgesia lowers maternal plasma epinephrine, whose beta-2 effect normally relaxes the uterus; its withdrawal leaves unopposed oxytocin and norepinephrine, producing hypertonus that reduces uteroplacental blood flow. The episode is usually transient and responds to intrauterine resuscitation: left uterine displacement, treating any hypotension, oxygen, stopping oxytocin, and uterine relaxation (terbutaline or nitroglycerin) if it persists.', '{}'::jsonb, 'Subspecialty Care', 'Neuraxial labor analgesia complications — CSE-associated fetal bradycardia from uterine tachysystole', 'medium', '[{"url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC9391899/","source":"Neuraxial labor analgesia: a literature review (PMC)"}]'::jsonb, 'sme_review', 'Obstetric'),
('authored-batch-r20-028', 'Obstetric', 'A 32-year-old woman at 19 weeks gestation requires laparoscopic appendectomy for acute appendicitis. She has no other medical history; vital signs and labs are normal. The obstetric team confirms a viable fetus with a normal preoperative fetal heart rate. The surgeon asks whether the operation should proceed now or be delayed, and the anesthesia team plans general anesthesia. Which statement best reflects appropriate management of this pregnant patient undergoing non-obstetric surgery?', '[{"text":"Surgery should be postponed until after delivery because all volatile anesthetics are proven human teratogens at clinical concentrations","label":"A","correct":false,"rationale":"Incorrect: no commonly used anesthetic agent has been definitively shown to be teratogenic in humans at clinical doses, and necessary surgery for acute appendicitis should not be deferred."},{"text":"Regional anesthesia is mandatory because general anesthesia is contraindicated in any pregnant patient after the first trimester","label":"B","correct":false,"rationale":"Incorrect: general anesthesia is not contraindicated in pregnancy, and the technique should be chosen on surgical and patient grounds, not by a blanket prohibition."},{"text":"Necessary surgery should proceed promptly with attention to avoiding maternal hypoxemia, hypotension, and hypocapnia or hypercapnia, aspiration prophylaxis and rapid-sequence induction as indicated, and left uterine displacement once the gravid uterus warrants it","label":"C","correct":true,"rationale":"Correct: an acutely needed operation should not be delayed, and fetal well-being is best protected by maintaining maternal oxygenation, normotension, and normocapnia while attending to aspiration risk and aortocaval compression."},{"text":"Nitrous oxide should be used as the primary agent to minimize fetal exposure to halogenated volatiles","label":"D","correct":false,"rationale":"Incorrect: nitrous oxide is not a preferred primary agent given theoretical concerns about methionine synthase inhibition, and there is no requirement to avoid halogenated volatiles, which are not proven human teratogens."},{"text":"Continuous intraoperative electronic fetal heart rate monitoring is required at this gestational age to guide anesthetic management","label":"E","correct":false,"rationale":"Incorrect: at 19 weeks the fetus is previable, so documenting fetal heart rate before and after the procedure is reasonable, but continuous intraoperative monitoring is reserved for viable gestations when intervention would be considered."}]'::jsonb, 'C', 'Up to about 2% of pregnant women undergo non-obstetric surgery, and urgent operations such as appendectomy should never be denied. When elective, surgery is ideally deferred to the second trimester or after delivery, but the priority for any anesthetic is maintaining the maternal physiology that supports the fetus: adequate oxygenation, normotension, and normocapnia, plus aspiration prophylaxis and left uterine displacement once the uterus is large enough. No standard anesthetic agent is a proven human teratogen at clinical doses. Continuous intraoperative fetal monitoring is generally reserved for viable gestations where the team would act on the tracing.', '{}'::jsonb, 'Subspecialty Care', 'Anesthesia for non-obstetric surgery during pregnancy — timing, agent safety, and fetal monitoring', 'hard', '[{"url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC12028341/","source":"Anesthetic Management of the Pregnant Patient Undergoing Non-Obstetric Surgery (PMC)"}]'::jsonb, 'sme_review', 'Obstetric'),
('authored-batch-r20-029', 'Obstetric', 'A 33-year-old G2P2 woman is in the PACU after a cesarean delivery under spinal anesthesia. She has a history of moderate persistent asthma and gestational hypertension, with a current blood pressure of 158/96 mmHg. The obstetrician reports ongoing uterine atony with brisk bleeding that has not responded adequately to an oxytocin infusion, and requests a second-line uterotonic. Which agent is the most appropriate next choice given this patient''s comorbidities?', '[{"text":"Methylergonovine (methylergometrine) 0.2 mg intramuscularly","label":"A","correct":false,"rationale":"Incorrect: as an ergot alkaloid with alpha-adrenergic activity it can cause severe vasoconstriction and a hypertensive crisis, so it is relatively contraindicated in this hypertensive patient."},{"text":"Carboprost (15-methyl prostaglandin F2-alpha) 250 mcg intramuscularly","label":"B","correct":false,"rationale":"Incorrect: carboprost is a potent bronchoconstrictor and is relatively contraindicated in asthma, making it a poor choice for this patient."},{"text":"A repeat bolus of intravenous ergonovine to rapidly augment uterine tone","label":"C","correct":false,"rationale":"Incorrect: ergonovine is the same ergot-alkaloid class as methylergonovine and carries the same hypertensive risk, so it is contraindicated here for the identical reason."},{"text":"Misoprostol (prostaglandin E1) 800 to 1000 mcg administered rectally","label":"D","correct":true,"rationale":"Correct: misoprostol lacks both the ergot-mediated hypertensive effect and the bronchoconstriction of carboprost, so it is the safest second-line uterotonic for a patient with both hypertension and asthma."},{"text":"Additional intravenous oxytocin given as a rapid undiluted bolus","label":"E","correct":false,"rationale":"Incorrect: atony has already failed to respond to oxytocin, and a rapid undiluted bolus can cause profound hypotension and tachycardia, so escalating oxytocin is neither effective nor safe."}]'::jsonb, 'D', 'When first-line oxytocin fails to control atonic postpartum hemorrhage, the choice of second-line uterotonic is dictated by comorbidities. Ergot alkaloids (methylergonovine, ergonovine) are alpha-adrenergic agonists that cause vasoconstriction and are relatively contraindicated in hypertension, while carboprost (15-methyl PGF2-alpha) causes bronchospasm and is relatively contraindicated in asthma. Misoprostol, a prostaglandin E1 analog, avoids both hazards and is the appropriate agent for a parturient who is both hypertensive and asthmatic.', '{}'::jsonb, 'Subspecialty Care', 'Postpartum hemorrhage — uterotonic selection by comorbidity (ergot in hypertension, carboprost in asthma)', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499988/","source":"Postpartum Hemorrhage (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Obstetric'),
('authored-batch-r20-030', 'Ambulatory', 'A 3-year-old, 15-kg boy is scheduled for elective bilateral myringotomy and tube placement at a freestanding ambulatory surgery center. On the morning of surgery his mother reports a clear runny nose and an occasional dry cough for the past two days. He is afebrile (37.1 C), playful and interactive, eating normally, with clear lungs and an SpO2 of 99% on room air. There is no history of asthma, prematurity, or secondhand smoke exposure, and the procedure is brief and does not require endotracheal intubation. Which of the following is the most appropriate management decision?', '[{"text":"Postpone the case and reschedule in 4 to 6 weeks because any current upper respiratory infection mandates cancellation","label":"A","correct":false,"rationale":"Blanket cancellation for an uncomplicated, afebrile URI without lower-airway signs is outdated and overly conservative, exposing the family to unnecessary rescheduling for a brief, low-risk procedure."},{"text":"Postpone the case for 2 weeks because the residual airway hyperreactivity window makes adverse events more likely if surgery proceeds now","label":"B","correct":false,"rationale":"Airway hyperreactivity can persist for weeks, but a child with only mild coryza and no high-risk features (fever, wheeze, purulent secretions, lethargy) does not meet criteria for postponement, and delaying does not reliably reduce risk for this low-acuity case."},{"text":"Proceed only after placing an endotracheal tube to definitively secure the airway against laryngospasm","label":"C","correct":false,"rationale":"Endotracheal intubation increases, rather than decreases, the risk of laryngospasm and bronchospasm in a child with a URI and is unnecessary for a brief myringotomy that is routinely done with a natural airway."},{"text":"Proceed but pretreat with intramuscular atropine and a prophylactic dose of intravenous dexamethasone to eliminate the risk of laryngospasm","label":"D","correct":false,"rationale":"Neither routine anticholinergic nor steroid prophylaxis reliably prevents laryngospasm, and committing to IM injection and IV access is excessive for an otherwise straightforward mask anesthetic in a mildly symptomatic child."},{"text":"Proceed with general anesthesia, favoring an inhalational technique with a natural airway and avoiding instrumentation of the trachea","label":"E","correct":true,"rationale":"Correct: with only mild, uncomplicated URI symptoms and no high-risk features, this brief myringotomy is appropriately performed under mask/natural-airway general anesthesia, which minimizes airway instrumentation and the associated risk of perioperative respiratory adverse events."}]'::jsonb, 'E', 'Children with a current or recent URI have roughly a 2- to 3-fold higher risk of perioperative respiratory adverse events (laryngospasm, bronchospasm, desaturation), but contemporary practice individualizes the decision rather than cancelling reflexively. Red flags that favor postponement include fever, mucopurulent secretions, wheezing or a moist productive cough, lethargy, and high-risk surgery; a child with mild clear rhinorrhea who is afebrile and active is generally safe to anesthetize. Minimizing airway instrumentation (natural airway/mask or LMA rather than an ETT) is a key risk-reduction strategy for a brief ambulatory procedure.', '{}'::jsonb, 'Subspecialty Care', 'Pediatric upper respiratory infection and perioperative respiratory adverse events in ambulatory surgery', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/pediatric-upper-respiratory-infection-and-anesthesia/","source":"Pediatric Upper Respiratory Infection and Anesthesia - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Ambulatory'),
('authored-batch-r20-031', 'Ambulatory', 'A 58-year-old man with hypertension undergoes an awake transesophageal echocardiogram in the GI/endoscopy suite of an ambulatory center. The posterior pharynx is anesthetized with a generous application of benzocaine spray before probe insertion. Fifteen minutes later he becomes anxious, dyspneic, and visibly dusky/gray, and his pulse oximeter reads 84% and will not rise above the mid-80s despite a non-rebreather mask at 15 L/min. He is hemodynamically stable with clear breath sounds. An arterial blood gas drawn on high-flow oxygen shows a PaO2 of 240 mmHg, and the blood sample appears chocolate-brown. Which of the following is the most appropriate next step?', '[{"text":"Administer methylene blue 1 to 2 mg/kg IV over about 5 minutes","label":"A","correct":true,"rationale":"Correct: the clinical picture (cyanosis refractory to oxygen, an SpO2 that plateaus near 85%, a normal/high PaO2, and chocolate-brown blood after an oxidizing topical anesthetic) is classic acquired methemoglobinemia, for which IV methylene blue 1 to 2 mg/kg is the first-line antidote."},{"text":"Proceed directly to emergent endotracheal intubation for impending respiratory failure","label":"B","correct":false,"rationale":"The patient is ventilating well with clear lungs and a high measured PaO2, so the problem is impaired oxygen delivery by oxidized hemoglobin, not a ventilation or airway-patency failure that intubation would correct."},{"text":"Increase supplemental oxygen and add PEEP via tight-fitting mask, anticipating the saturation will normalize","label":"C","correct":false,"rationale":"Methemoglobin cannot carry oxygen regardless of how high the dissolved PaO2 is, so escalating oxygen delivery will not raise the SpO2, which is why the saturation is refractory in the first place."},{"text":"Transfuse one unit of packed red blood cells to improve oxygen-carrying capacity","label":"D","correct":false,"rationale":"Transfusion is not the initial treatment for acute drug-induced methemoglobinemia; the offending oxidant should be stopped and methylene blue given, with transfusion or exchange reserved for refractory or methylene-blue-contraindicated cases."},{"text":"Give intravenous lipid emulsion 20% as rescue for local anesthetic systemic toxicity","label":"E","correct":false,"rationale":"Lipid emulsion treats systemic toxicity from amide local anesthetics (e.g., CNS/cardiac collapse from bupivacaine), not the hemoglobin oxidation caused by an ester topical agent like benzocaine."}]'::jsonb, 'A', 'Benzocaine and other topical anesthetics are well-known oxidizing agents that can convert hemoglobin iron from the ferrous to the ferric (methemoglobin) state, impairing oxygen carriage. The hallmark is cyanosis with an SpO2 that plateaus around 85% and is refractory to supplemental oxygen, a normal or high measured PaO2, and chocolate-brown arterial blood; co-oximetry confirms an elevated methemoglobin fraction. First-line treatment is methylene blue 1 to 2 mg/kg IV over about 5 minutes after removing the offending agent, with caution (and reduced efficacy) in G6PD deficiency.', '{}'::jsonb, 'Subspecialty Care', 'Methemoglobinemia from topical (benzocaine) anesthetic during ambulatory/endoscopy sedation', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK537317/","source":"Methemoglobinemia - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Ambulatory'),
('authored-batch-r20-032', 'Ambulatory', 'A 34-year-old healthy woman (ASA II, well-controlled hypothyroidism) is recovering after an outpatient knee arthroscopy under general anesthesia with an LMA. Forty-five minutes into Phase I recovery she opens her eyes to voice and moves all four extremities on command, breathes deeply and coughs freely, has a blood pressure within 15% of her preoperative baseline, and reads 98% on room-air pulse oximetry, giving her a modified Aldrete score of 10. She still feels groggy and has not yet voided, ambulated, or tolerated oral intake. Her ride home is present. Which statement best describes her readiness for discharge home from the ambulatory facility?', '[{"text":"She is ready for immediate discharge home because a maximal Aldrete score of 10 establishes home-readiness","label":"A","correct":false,"rationale":"The Aldrete score assesses recovery from anesthesia sufficient to leave Phase I PACU, not readiness to go home, so a perfect score alone does not authorize discharge to the street."},{"text":"She can be discharged once she also meets home-readiness criteria such as the Post-Anesthetic Discharge Scoring System, with stable vitals, controlled pain and nausea, and a responsible escort","label":"B","correct":true,"rationale":"Correct: home-readiness is assessed with a discharge-specific tool like PADSS, which evaluates vital sign stability, ambulation, pain, nausea/vomiting, and surgical bleeding, and requires a responsible adult escort before street discharge."},{"text":"She must remain until a documented spontaneous void is achieved, as voiding is a universal mandatory discharge criterion for all outpatients","label":"C","correct":false,"rationale":"Mandatory voiding before discharge is no longer required for low-risk patients without risk factors for urinary retention; it is selectively applied rather than being a universal criterion."},{"text":"She must be observed a fixed minimum of 3 additional hours regardless of her clinical status before any outpatient can be discharged","label":"D","correct":false,"rationale":"Modern fast-track pathways individualize discharge by validated criteria rather than imposing an arbitrary fixed observation time on every patient."},{"text":"She requires a mandatory trial of oral fluids, and failure to tolerate intake should delay discharge in every ambulatory patient","label":"E","correct":false,"rationale":"Routine forced oral intake is not required and may worsen nausea; tolerating fluids is not a mandatory discharge criterion for all outpatients under current guidance."}]'::jsonb, 'B', 'The Aldrete score (activity, respiration, circulation, consciousness, and oxygen saturation) gauges recovery adequate to leave Phase I PACU, with a threshold of 8 or higher, but it does not establish readiness to go home. Discharge home from an ambulatory facility is judged with a home-readiness instrument such as the Post-Anesthetic Discharge Scoring System (PADSS), which incorporates vital sign stability, ambulation, pain, nausea/vomiting, and surgical bleeding, plus a responsible escort. Routine mandatory voiding and oral intake have been removed as universal requirements for low-risk patients to facilitate efficient, safe fast-track discharge.', '{}'::jsonb, 'Subspecialty Care', 'Ambulatory discharge criteria and fast-tracking (Aldrete vs. PADSS home-readiness)', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK594237/","source":"Aldrete Scoring System - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Ambulatory'),
('authored-batch-r20-033', 'Orthopedic, Urology & GYN', 'A 64-year-old man (BMI 19, hemoglobin 11.2 g/dL) undergoes a 7-hour posterior multilevel lumbar decompression and instrumented fusion in the prone position on a Wilson frame. Anesthesia is maintained with deliberate hypotension (MAP 60-65 mmHg) to limit blood loss, which reaches 2.4 L; he receives 6 L of crystalloid and 2 units of packed red cells. On emergence he reports painless bilateral loss of vision; pupillary light reflexes are sluggish, the anterior segments and fundi appear normal, and an ophthalmology exam shows no globe compression injury. Which factor in this case most directly contributed to his postoperative visual loss?', '[{"text":"Direct external compression of the globes against the headrest causing central retinal artery occlusion","label":"A","correct":false,"rationale":"Normal anterior segments, a normal fundus, and an exam excluding globe compression argue against central retinal artery occlusion from external pressure, which classically shows a cherry-red macula and is usually unilateral."},{"text":"Embolic occlusion of the ophthalmic artery from bone-cement particulate","label":"B","correct":false,"rationale":"No cement is used in posterior decompression/fusion of this type, and an arterial embolic event would not produce the bilateral, perfusion-pattern injury seen here."},{"text":"Prolonged dependent positioning with venous congestion, hemodilution, and sustained hypotension reducing optic nerve perfusion (posterior ischemic optic neuropathy)","label":"C","correct":true,"rationale":"Long prone spine cases with large blood loss, anemia/hemodilution, deliberate hypotension, and high crystalloid volume are the recognized risk profile for posterior ischemic optic neuropathy, which presents as painless visual loss with an initially normal fundus."},{"text":"Cortical blindness from an intraoperative occipital watershed infarct","label":"D","correct":false,"rationale":"Cortical blindness spares the pupillary light reflex (which is sluggish here) and would typically yield other neurologic deficits, making it a less fitting explanation than an optic nerve mechanism."},{"text":"Acute angle-closure glaucoma precipitated by anticholinergic premedication","label":"E","correct":false,"rationale":"Angle-closure glaucoma causes a painful red eye with a mid-dilated fixed pupil and elevated intraocular pressure, none of which match this painless presentation with normal anterior segments."}]'::jsonb, 'C', 'Perioperative visual loss after prolonged prone spine surgery is most often posterior ischemic optic neuropathy (ION), not globe compression. The optic nerve becomes ischemic when venous congestion from dependent head positioning, anemia/hemodilution, sustained hypotension, and large-volume resuscitation collectively lower optic nerve perfusion pressure. Risk-reduction strategies include staging very long cases, limiting crystalloid and blood loss, keeping the head at or above heart level, and avoiding unnecessary deliberate hypotension in high-risk patients.', '{}'::jsonb, 'Subspecialty Care', 'Orthopedics — perioperative visual loss (ischemic optic neuropathy) after prone spine surgery', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/postoperative-visual-loss/","source":"OpenAnesthesia — Postoperative Visual Loss"}]'::jsonb, 'sme_review', 'Orthopedic, Urology & GYN'),
('authored-batch-r20-034', 'Orthopedic, Urology & GYN', 'A 68-year-old man with well-controlled hypertension undergoes robot-assisted laparoscopic radical prostatectomy. He is in steep (≈40°) Trendelenburg with CO2 pneumoperitoneum, and his arms are tucked. Three hours into the case, peak inspiratory pressure has risen from 22 to 34 cmH2O, EtCO2 is 48 mmHg despite increased minute ventilation, and the surgeon notes the surgical field is now partly obscured. As you prepare for extubation after the robot is undocked and the patient is returned to supine, which intraoperative change is the most important to reassess before removing the tube?', '[{"text":"A reassuring leak around the cuff confirming the airway is safe to extubate immediately","label":"A","correct":false,"rationale":"Prolonged steep Trendelenburg with pneumoperitoneum produces airway and facial/laryngeal edema, so the absence of a cuff leak (not its presence) is the concerning finding and a leak should be actively checked, not assumed."},{"text":"A fall in intraocular pressure expected once pneumoperitoneum is released","label":"B","correct":false,"rationale":"Intraocular pressure rises rather than falls in steep Trendelenburg with pneumoperitoneum, and although it is a real concern it is not the issue that governs the timing or safety of extubation."},{"text":"Cephalad migration of the endotracheal tube causing endobronchial intubation","label":"C","correct":false,"rationale":"Tube tip migration toward the carina can occur in steep Trendelenburg and pneumoperitoneum, but the tip moves caudad (toward a mainstem) rather than cephalad and is best detected during the case, not as the decisive pre-extubation airway check."},{"text":"Development of upper-airway and laryngeal edema that may compromise the airway after extubation","label":"D","correct":true,"rationale":"Dependent head positioning with raised venous and intra-abdominal pressure causes facial, conjunctival, and airway edema, so confirming airway patency (e.g., a cuff-leak test) before extubation is the priority safety step."},{"text":"Loss of functional residual capacity that fully resolves the instant the patient is made supine","label":"E","correct":false,"rationale":"Reduced functional residual capacity and compliance do not normalize instantly on returning to supine, so assuming immediate recovery is unsafe and does not address the airway-edema risk that determines extubation readiness."}]'::jsonb, 'D', 'Steep Trendelenburg combined with CO2 pneumoperitoneum raises central venous and intra-abdominal pressure, producing dependent edema of the face, conjunctivae, tongue, and larynx along with reduced pulmonary compliance and a higher EtCO2. The most consequential pre-extubation concern is airway edema: a patient who looked normal at induction may have significant supraglottic swelling after hours of positioning. Confirm a cuff leak and full reversal, keep the patient head-up, and have a plan for reintubation or delayed extubation if edema is suspected.', '{}'::jsonb, 'Subspecialty Care', 'Urology — physiologic effects of steep Trendelenburg and pneumoperitoneum during robotic prostatectomy', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/patient-positioning-physiologic-effects/","source":"OpenAnesthesia — Patient Positioning: Physiologic Effects"}]'::jsonb, 'sme_review', 'Orthopedic, Urology & GYN'),
('authored-batch-r20-035', 'Orthopedic, Urology & GYN', 'During a cesarean delivery under spinal anesthesia, the obstetrician asks for a uterotonic immediately after delivery of the placenta. The CAA gives a rapid intravenous bolus of 10 units of oxytocin. Within 30 seconds the blood pressure falls from 118/72 to 78/40 mmHg, heart rate rises from 84 to 128/min, and the patient reports chest tightness and nausea. The uterus is now firm. What is the most appropriate explanation and immediate management?', '[{"text":"This is an anaphylactic reaction to oxytocin; give intramuscular epinephrine 0.5 mg and stop all uterotonics","label":"A","correct":false,"rationale":"A firm uterus with isolated transient hypotension/tachycardia immediately after a rapid bolus reflects oxytocin''s direct vasodilatory effect rather than anaphylaxis, which would more typically include bronchospasm, urticaria, and airway edema."},{"text":"The hypotension is from a high spinal; immediately intubate and start chest compressions","label":"B","correct":false,"rationale":"The patient is conscious with a tachycardic, perfusing rhythm and the event began seconds after the oxytocin bolus, so a high spinal requiring intubation and CPR does not fit the timeline or presentation."},{"text":"Switch immediately to carboprost (15-methyl PGF2α) as the first-line replacement regardless of history","label":"C","correct":false,"rationale":"Carboprost is a second-line agent reserved for ongoing atony and is contraindicated in asthma, so reflexively substituting it here—where the uterus is already firm—is inappropriate."},{"text":"Give methylergonovine 0.2 mg IV push to counteract the hypotension","label":"D","correct":false,"rationale":"Methylergonovine should be given intramuscularly and is contraindicated in hypertension and avoided as an IV push because it can cause severe vasospasm and a hypertensive crisis, so it is not the remedy for oxytocin-induced hypotension."},{"text":"This is oxytocin-induced vasodilation and reflex tachycardia from rapid bolus administration; support blood pressure with a vasopressor and fluids and give future oxytocin as a slow infusion","label":"E","correct":true,"rationale":"A rapid oxytocin bolus causes direct systemic vasodilation with reflex tachycardia and can cause chest tightness, so the correct response is hemodynamic support and giving subsequent oxytocin slowly or as a dilute infusion."}]'::jsonb, 'E', 'Oxytocin given as a rapid IV bolus causes direct vascular smooth muscle relaxation, producing transient hypotension, reflex tachycardia, flushing, and occasionally chest tightness; large bolus doses can precipitate dangerous cardiovascular instability, especially in hypovolemic or cardiac patients. Because the uterus is already contracted, management is supportive: a vasopressor (e.g., phenylephrine), fluids, and giving oxytocin as a slow dilute infusion rather than a bolus. Second-line uterotonics such as methylergonovine (avoid in hypertension, give IM) or carboprost (avoid in asthma) are reserved for persistent atony, not for treating oxytocin''s hemodynamic side effects.', '{}'::jsonb, 'Subspecialty Care', 'Obstetrics — uterotonic pharmacology: oxytocin bolus hemodynamics and uterotonic selection', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK507848/","source":"Oxytocin — StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Orthopedic, Urology & GYN'),
('authored-batch-r20-036', 'Regional & Pain', 'A 71-year-old woman is scheduled for elective right total knee arthroplasty, and the team plans a single-shot spinal anesthetic followed by a continuous adductor canal catheter. For postoperative venous thromboembolism prophylaxis she has been receiving enoxaparin 30 mg subcutaneously every 12 hours; her most recent dose was administered 6 hours ago. Her platelet count is 240,000/microL, INR 1.0, and creatinine 0.8 mg/dL. According to the current ASRA antithrombotic guideline, what is the most appropriate management before placing the neuraxial block?', '[{"text":"Delay the spinal until at least 12 hours after the last prophylactic enoxaparin dose","label":"A","correct":true,"rationale":"Correct; ASRA recommends a minimum 12-hour interval after a prophylactic (low-dose) LMWH dose before performing a neuraxial procedure."},{"text":"Proceed with the spinal now, since prophylactic-dose enoxaparin does not require any delay","label":"B","correct":false,"rationale":"Incorrect; even prophylactic (twice-daily 30 mg) enoxaparin produces residual anti-Xa activity, so a defined interval is required before needle placement."},{"text":"Delay the spinal until at least 24 hours after the last dose because this is a therapeutic regimen","label":"C","correct":false,"rationale":"Incorrect; 30 mg twice daily is a prophylactic, not therapeutic, dose, so the 24-hour interval reserved for therapeutic dosing does not apply."},{"text":"Check an anti-Xa level and proceed only if it is undetectable","label":"D","correct":false,"rationale":"Incorrect; ASRA does not recommend routine anti-Xa monitoring to time neuraxial procedures because the assay is neither standardized nor predictive of bleeding risk."},{"text":"Abandon neuraxial anesthesia entirely and perform general anesthesia because LMWH is an absolute contraindication","label":"E","correct":false,"rationale":"Incorrect; LMWH is not an absolute contraindication, and neuraxial anesthesia is appropriate once the recommended time interval has elapsed."}]'::jsonb, 'A', 'The ASRA antithrombotic guideline sets dose-based timing intervals to minimize spinal/epidural hematoma risk. For prophylactic (low-dose) LMWH such as enoxaparin 30 mg twice daily, a minimum 12-hour delay after the last dose is required before neuraxial needle or catheter placement, whereas therapeutic dosing (e.g., 1 mg/kg twice daily) requires 24 hours. Routine anti-Xa monitoring is not recommended for timing. The first postoperative LMWH dose and catheter removal must also be separated from the block by appropriate intervals.', '{}'::jsonb, 'Subspecialty Care', 'Neuraxial anesthesia in the anticoagulated patient (ASRA LMWH timing)', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/regional-anesthesia-in-patients-receiving-antithrombotic-or-thrombolytic-therapy-part-1/","source":"Regional Anesthesia in Patients Receiving Antithrombotic or Thrombolytic Therapy: Part 1"}]'::jsonb, 'sme_review', 'Regional & Pain'),
('authored-batch-r20-037', 'Regional & Pain', 'A 64-year-old man with severe COPD (FEV1 42% predicted, baseline room-air SpO2 of 92%) presents for arthroscopic rotator cuff repair of the left shoulder. The attending proposes a single-shot ultrasound-guided interscalene brachial plexus block with 20 mL of 0.5% ropivacaine for surgical anesthesia and analgesia. The student anesthetist is concerned about a specific predictable physiologic effect of this block in this patient. Which statement best characterizes the risk that should most influence the anesthetic plan?', '[{"text":"Phrenic nerve involvement is rare with ultrasound guidance, so no pulmonary precautions are needed","label":"A","correct":false,"rationale":"Incorrect; although ultrasound and lower volumes reduce the incidence, phrenic spread remains very common and cannot be assumed absent."},{"text":"Ipsilateral hemidiaphragmatic paresis is nearly universal and may not be tolerated given his limited pulmonary reserve","label":"B","correct":true,"rationale":"Correct; phrenic nerve spread causes hemidiaphragmatic paresis in close to 100% of standard interscalene blocks, which can precipitate respiratory decompensation in a patient with severe COPD."},{"text":"The primary concern is contralateral diaphragm paralysis causing bilateral respiratory failure","label":"C","correct":false,"rationale":"Incorrect; the block affects the ipsilateral phrenic nerve only, producing unilateral, not bilateral, diaphragmatic dysfunction."},{"text":"Recurrent laryngeal nerve block will cause complete airway obstruction in most patients","label":"D","correct":false,"rationale":"Incorrect; recurrent laryngeal involvement causes hoarseness and is usually well tolerated, and it is not the dominant respiratory risk of this block."},{"text":"The block reliably improves his vital capacity by relieving shoulder splinting","label":"E","correct":false,"rationale":"Incorrect; interscalene block does not augment vital capacity and in fact typically reduces it by roughly 25-30% through diaphragmatic paresis."}]'::jsonb, 'B', 'Because the phrenic nerve lies on the anterior scalene muscle immediately adjacent to the brachial plexus at the interscalene level, anterior spread of local anesthetic produces ipsilateral hemidiaphragmatic paresis in nearly all standard-volume interscalene blocks, reducing vital capacity by about 25-30%. Patients with severe COPD or other marginal pulmonary reserve may not tolerate this and can decompensate. Lower local anesthetic volumes, more distal injection, or alternative blocks (e.g., superior trunk or supraclavicular approaches) reduce but do not eliminate the risk, so the technique should be reconsidered in this patient.', '{}'::jsonb, 'Subspecialty Care', 'Upper extremity blocks: interscalene block and phrenic nerve/respiratory effects', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/interscalene-block/","source":"Interscalene Block"}]'::jsonb, 'sme_review', 'Regional & Pain'),
('authored-batch-r20-038', 'Cardiac', 'A 68-year-old woman is separating from cardiopulmonary bypass after a 3-vessel coronary artery bypass graft. As protamine is administered to reverse heparin (1 mg per 100 units), the surgeon notes the heart distending and the field becoming engorged; arterial pressure falls from 92/54 to 41/26 mmHg, central venous pressure rises to 22 mmHg, and the pulmonary artery pressure climbs sharply. There is no rash or bronchospasm. What is the most appropriate immediate management?', '[{"text":"Continue the protamine and give a 20% lipid emulsion bolus over 2-3 minutes","label":"A","correct":false,"rationale":"Lipid emulsion treats local anesthetic systemic toxicity, not a protamine reaction, and continuing protamine would worsen the pulmonary vasoconstriction."},{"text":"Administer a large fluid bolus and place the patient in steep Trendelenburg","label":"B","correct":false,"rationale":"Aggressive volume into an acutely failing, pressure-overloaded right ventricle would further distend it and worsen failure rather than treat the underlying pulmonary vasoconstriction."},{"text":"Stop the protamine infusion, return to full cardiopulmonary bypass support, and re-heparinize","label":"C","correct":true,"rationale":"Correct: this picture is a catastrophic protamine reaction with acute pulmonary vasoconstriction and right-heart failure, and the safest rescue is to stop protamine, re-establish bypass for hemodynamic support, and re-heparinize for the circuit."},{"text":"Give a rapid bolus of additional protamine to ensure complete heparin neutralization","label":"D","correct":false,"rationale":"More protamine intensifies the very reaction causing pulmonary hypertension and right-heart failure and is contraindicated."},{"text":"Administer intravenous phenylephrine alone and continue weaning from bypass","label":"E","correct":false,"rationale":"Phenylephrine can raise systemic pressure but does not address the catastrophic pulmonary vasoconstriction and right ventricular distention, and proceeding off bypass risks arrest."}]'::jsonb, 'C', 'Protamine can cause a spectrum of reactions; the most feared is a Type III catastrophic pulmonary vasoconstriction with acute right ventricular failure, recognized by rising CVP/PA pressures, RV distention, and systemic hypotension as protamine is given. Management is to stop the protamine, re-heparinize, and resume cardiopulmonary bypass to support the circulation while the reaction is treated (pulmonary vasodilators, inotropes). Slowing or pausing protamine administration and giving it through a peripheral line over 10-15 minutes can reduce the risk of these reactions.', '{}'::jsonb, 'Subspecialty Care', 'Protamine reactions and pulmonary vasoconstriction during separation from cardiopulmonary bypass', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/protamine-reactions/","source":"Protamine Reactions (OpenAnesthesia)"}]'::jsonb, 'sme_review', 'Cardiac'),
('authored-batch-r20-039', 'Cardiac', 'A 58-year-old man with metastatic lung cancer presents for an urgent subxiphoid pericardial window. He is dyspneic and anxious, sitting upright. Vitals: HR 122/min, BP 88/64 mmHg with a 16 mmHg pulsus paradoxus, distended neck veins, and muffled heart sounds. Echocardiography shows a large circumferential pericardial effusion with right atrial systolic collapse and a plethoric inferior vena cava. The surgeon requests general anesthesia. Which anesthetic plan best matches the hemodynamic goals for this patient before the pericardium is opened?', '[{"text":"Induce with a high-dose propofol bolus and immediately initiate controlled positive-pressure ventilation","label":"A","correct":false,"rationale":"High-dose propofol drops preload and afterload while positive-pressure ventilation further reduces venous return, a combination that can precipitate cardiovascular collapse in tamponade."},{"text":"Perform a slow neuraxial-based technique to lower systemic vascular resistance and afterload","label":"B","correct":false,"rationale":"Reducing SVR is exactly the wrong goal in tamponade, where maintaining afterload and preload is essential, and neuraxial sympathectomy could cause collapse."},{"text":"Deepen anesthesia with high-dose volatile agent to blunt the tachycardia before incision","label":"C","correct":false,"rationale":"Deliberately slowing the compensatory tachycardia and adding the vasodilation/myocardial depression of high-dose volatile agent removes the patient''s primary compensatory mechanisms."},{"text":"Prep and drape awake, maintain spontaneous ventilation, and induce with ketamine while preserving preload, heart rate, and afterload","label":"D","correct":true,"rationale":"Correct: the goals are ''full, fast, and tight'' — maintain preload, heart rate, and SVR — and preparing the patient before induction with a hemodynamically stable agent like ketamine that preserves sympathetic tone and spontaneous ventilation is the safest approach."},{"text":"Administer a beta-blocker to control the heart rate and reduce myocardial oxygen demand","label":"E","correct":false,"rationale":"In tamponade, fixed stroke volume makes cardiac output rate-dependent, so blunting the compensatory tachycardia with a beta-blocker can cause profound hypotension."}]'::jsonb, 'D', 'In cardiac tamponade, stroke volume is fixed and low, so cardiac output depends on maintaining a relatively high heart rate, adequate preload, and adequate afterload — summarized as ''full, fast, and tight.'' Induction of general anesthesia and positive-pressure ventilation are the highest-risk moments because they reduce venous return and abolish sympathetic compensation, which can cause arrest before the pericardium is decompressed. Prepping/draping the patient awake and using a hemodynamically stable agent such as ketamine while preserving spontaneous ventilation, with surgical decompression ready, is the preferred approach.', '{}'::jsonb, 'Subspecialty Care', 'Cardiac tamponade physiology and induction hemodynamics (full, fast, tight)', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/cardiac-tamponade-anesth-management/","source":"Cardiac Tamponade (OpenAnesthesia)"}]'::jsonb, 'sme_review', 'Cardiac'),
('authored-batch-r20-040', 'Monitoring, Equipment & Physiology', 'During setup for a general anesthetic, a CAA hangs what is labeled as an oxygen E-cylinder on the right-hand hanger yoke of the anesthesia machine. The cylinder seats fully and the valve opens, but the CAA notices the yoke pins did not engage any holes and a Bodok seal was not in place. The Pin Index Safety System uses two pins per gas placed in a semicircular arc, with oxygen assigned positions 2 and 5. Which of the following BEST explains how a cylinder containing a hypoxic gas could nonetheless be seated and delivered through this oxygen yoke?', '[{"text":"The Bodok seal itself carries the indexing holes, so omitting it bypasses the pin index","label":"A","correct":false,"rationale":"Incorrect: the Bodok seal is only a sealing washer between valve and yoke and plays no role in gas-specific indexing."},{"text":"Oxygen pin positions 2 and 5 are shared with nitrous oxide, so the two cylinders are interchangeable at the yoke","label":"B","correct":false,"rationale":"Incorrect: nitrous oxide is assigned positions 3 and 5, a different pin pattern, so it cannot normally seat on an oxygen yoke when pins are intact."},{"text":"The Diameter Index Safety System on the yoke failed, allowing the pins to retract","label":"C","correct":false,"rationale":"Incorrect: the Diameter Index Safety System applies to threaded low-pressure pipeline connections, not to the pin-indexed high-pressure hanger yoke."},{"text":"E-cylinders are too small to engage the pin index, which functions only on large H-cylinders","label":"D","correct":false,"rationale":"Incorrect: the pin index system is specifically the safeguard for small cylinders on hanger yokes, whereas large H-cylinders use threaded (DISS-type) connections at the manifold."},{"text":"The pins on the yoke were removed or broken off, allowing a non-indexed valve to seat fully","label":"E","correct":true,"rationale":"Correct: missing or broken yoke pins defeat the Pin Index Safety System, permitting a cylinder of any gas to seat and flow, which is a recognized cause of wrong-gas delivery."}]'::jsonb, 'E', 'The Pin Index Safety System prevents wrong-gas connection by requiring two yoke pins to mate with two correspondingly drilled holes on the cylinder valve, with each gas assigned a unique pin pattern (oxygen 2,5; nitrous oxide 3,5; air 1,5). The system is defeated only when the yoke pins are missing, bent, or broken, or when extra Bodok seals are stacked to lift the valve off the pins; either allows a non-matching valve to seat and flow. The Bodok seal is purely a gas-tight washer and provides no indexing. Recognizing that a cylinder seated without pin engagement is unsafe should prompt immediate removal before any case proceeds.', '{}'::jsonb, 'Subspecialty Care', 'Medical gas supply and cylinder safety (Pin Index Safety System)', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK532908/","source":"Pin Index Safety System (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Monitoring, Equipment & Physiology'),
('authored-batch-r20-041', 'Monitoring, Equipment & Physiology', 'A 64-year-old man is undergoing laparoscopic sigmoid colectomy under general endotracheal anesthesia with volume-controlled ventilation. Forty minutes into the case, with no change in ventilator settings or surgical CO2 insufflation, the end-tidal CO2 abruptly falls from 38 mm Hg to 6 mm Hg over two breaths and the waveform nearly flattens. The pulse oximeter plethysmograph becomes dampened, the blood pressure is now unobtainable by the cuff, and the arterial line traces a narrow, low pulse pressure. Breath sounds are present bilaterally and the circuit is intact with normal peak airway pressures. Which is the MOST likely explanation for this sudden drop in end-tidal CO2?', '[{"text":"Acute reduction in cardiac output (cardiovascular collapse) reducing pulmonary blood flow","label":"A","correct":true,"rationale":"Correct: a sudden fall in EtCO2 with preserved bilateral breath sounds, intact circuit, and normal airway pressures alongside loss of pulse pressure points to abruptly reduced pulmonary perfusion delivering less CO2 to the alveoli."},{"text":"Esophageal intubation","label":"B","correct":false,"rationale":"Incorrect: esophageal intubation produces an absent or rapidly vanishing waveform from the start of ventilation, not a sudden mid-case drop after 40 minutes of normal capnography."},{"text":"Breathing-circuit disconnection at the Y-piece","label":"C","correct":false,"rationale":"Incorrect: a disconnection would also abolish chest rise, trigger low-pressure/apnea alarms, and drop peak airway pressures, none of which are present here."},{"text":"Acute bronchospasm","label":"D","correct":false,"rationale":"Incorrect: bronchospasm produces a sloping (shark-fin) phase III with rising peak airway pressures and wheezing, not a near-zero flat waveform with normal airway pressures."},{"text":"Hypoventilation from a leaking endotracheal tube cuff","label":"E","correct":false,"rationale":"Incorrect: a cuff leak causes a loss of tidal volume and audible leak with a gradually altered capnogram, not an abrupt fall to near zero with hemodynamic collapse."}]'::jsonb, 'A', 'End-tidal CO2 depends on adequate alveolar ventilation AND pulmonary blood flow to deliver CO2 to the alveoli. When ventilation and the circuit are demonstrably intact (bilateral breath sounds, normal peak pressures, no disconnect alarm) but EtCO2 abruptly collapses with simultaneous loss of pulse pressure, the unifying cause is a sudden fall in cardiac output and thus pulmonary perfusion. This pattern is the capnographic hallmark of cardiovascular collapse (including massive pulmonary or gas embolism and cardiac arrest) and should trigger an immediate hemodynamic and ACLS-oriented response rather than an airway troubleshooting sequence.', '{}'::jsonb, 'Subspecialty Care', 'Capnography / end-tidal CO2 waveform interpretation', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK539754/","source":"Capnography and Respiratory Monitoring (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Monitoring, Equipment & Physiology'),
('authored-batch-r20-042', 'Monitoring, Equipment & Physiology', 'A 72-year-old woman with aortic stenosis has a central venous catheter placed for a Whipple procedure. After an uneventful induction she is in normal sinus rhythm and the CVP traces a normal a-c-v pattern with a mean of 8 mm Hg. Midway through the dissection, she develops a regular narrow-complex tachycardia at 130/min; the anesthesia provider notes the P waves are no longer clearly visible on the ECG, the blood pressure falls, and the CVP monitor now shows large, regular pressure spikes occurring with each beat. Which mechanism BEST explains these new giant (cannon) a waves on the CVP tracing?', '[{"text":"Tricuspid regurgitation is producing tall systolic v waves from regurgitant flow into the atrium","label":"A","correct":false,"rationale":"Incorrect: tricuspid regurgitation produces tall v waves with loss of the x descent, not a-wave cannon waves, and would not be newly precipitated simply by a junctional tachycardia."},{"text":"The right atrium is contracting against a closed tricuspid valve because atrial and ventricular contraction are no longer properly sequenced","label":"B","correct":true,"rationale":"Correct: cannon a waves arise when the atrium contracts against a closed tricuspid valve, which occurs in junctional/AV-dissociated rhythms where atrial and ventricular systole coincide, matching the loss of visible P waves and the regular large CVP spikes."},{"text":"Loss of organized atrial contraction has abolished the a wave entirely, as occurs in atrial fibrillation","label":"C","correct":false,"rationale":"Incorrect: this describes absent a waves seen in atrial fibrillation, the opposite of the large regular a waves described."},{"text":"Right ventricular hypertrophy is causing chronically large a waves from impaired ventricular filling","label":"D","correct":false,"rationale":"Incorrect: while RVH can enlarge a waves chronically, it would not appear acutely and synchronously with a new rhythm change and loss of P waves."},{"text":"Catheter whip from the tachycardia is creating artifactual pressure spikes unrelated to atrial mechanics","label":"E","correct":false,"rationale":"Incorrect: catheter whip produces irregular high-frequency artifact, not reproducible large a waves timed to each cardiac cycle with the atrium contracting against a closed valve."}]'::jsonb, 'B', 'The CVP a wave reflects right atrial contraction. When atrioventricular synchrony is lost, as in a junctional rhythm or other AV dissociation, the atrium intermittently or regularly contracts while the tricuspid valve is closed, generating a giant retrograde pressure wave known as a cannon a wave. The clinical clues here, a regular narrow-complex tachycardia with loss of visible P waves and new large beat-to-beat CVP spikes, fit a junctional rhythm producing regular cannon waves. Recognizing this is important because the loss of the atrial kick is especially poorly tolerated in a patient with aortic stenosis, explaining the accompanying hypotension.', '{}'::jsonb, 'Subspecialty Care', 'Central venous pressure waveform interpretation', 'hard', '[{"url":"https://www.openanesthesia.org/cvp_waveform_components/","source":"Central Venous Pressure and Pulmonary Artery Wedge Pressure (OpenAnesthesia)"}]'::jsonb, 'sme_review', 'Monitoring, Equipment & Physiology'),
('authored-batch-r20-043', 'Geriatric', 'A 79-year-old man is undergoing emergent open repair of an incarcerated inguinal hernia under general anesthesia. His history includes well-controlled hypertension, mild hearing loss, and a baseline Montreal Cognitive Assessment (MoCA) score of 24. The case is uncomplicated. On postoperative day 1 the nurse reports that he is intermittently inattentive, believes he is at home, and was agitated overnight but calm and oriented this morning. Vitals are stable, SpO2 96% on room air, and a basic metabolic panel, glucose, and urinalysis are unremarkable. Which feature MOST strongly distinguishes this presentation as postoperative delirium rather than postoperative cognitive dysfunction or dementia?', '[{"text":"The presence of a low baseline MoCA score of 24 before surgery","label":"A","correct":false,"rationale":"A preoperative MoCA of 24 indicates mild baseline cognitive impairment, which is a risk factor for delirium but is not itself the distinguishing feature of the acute syndrome."},{"text":"The agitation occurring specifically at night","label":"B","correct":false,"rationale":"Nocturnal worsening (sundowning) is common in delirium but also occurs in dementia, so it does not by itself establish the diagnosis."},{"text":"The acute onset and fluctuating course of inattention and altered awareness over hours to a day","label":"C","correct":true,"rationale":"Correct — delirium is defined by an acute, fluctuating disturbance of attention and awareness, distinguishing it from the gradual, stable decline of dementia and the subtle, persistent deficits of postoperative cognitive dysfunction."},{"text":"The patient''s age greater than 75 years","label":"D","correct":false,"rationale":"Advanced age is a major predisposing risk factor for delirium but is not a diagnostic feature of the acute syndrome itself."},{"text":"The need to formally measure deficits weeks later with neuropsychological testing","label":"E","correct":false,"rationale":"Delayed neuropsychological testing is how postoperative cognitive dysfunction is detected, not how acute delirium is identified at the bedside."}]'::jsonb, 'C', 'Postoperative delirium is a clinical diagnosis defined by an ACUTE, FLUCTUATING disturbance of attention and awareness with a change from baseline cognition, often screened with tools such as the Confusion Assessment Method (CAM). This temporal pattern separates it from dementia (insidious, progressive, stable over a single day) and from postoperative cognitive dysfunction (a more subtle, persistent decline detected only by formal neuropsychological testing weeks later). Predisposing factors (older age, baseline cognitive impairment, sensory deficits) raise risk but are not the diagnostic criterion; first-line management is to identify and treat precipitants and apply nonpharmacologic measures (reorientation, sleep hygiene, early mobilization, sensory aids) before considering pharmacologic therapy.', '{}'::jsonb, 'Subspecialty Care', 'Perioperative neurocognitive disorders — distinguishing postoperative delirium from POCD/dementia', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK534831/","source":"Postoperative Delirium (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Geriatric'),
('authored-batch-r20-044', 'Geriatric', 'An 83-year-old woman (weight 52 kg) presents for elective total hip arthroplasty under general anesthesia. Her comorbidities include controlled hypertension and an estimated glomerular filtration rate of 48 mL/min/1.73 m2. You plan a propofol induction and intend to maintain neuromuscular blockade. Considering the physiologic changes of aging, which dosing strategy is MOST appropriate?', '[{"text":"Use a standard adult induction dose of propofol per kilogram because central nervous system sensitivity is unchanged with age","label":"A","correct":false,"rationale":"The aged brain is more sensitive to propofol and elderly patients have a smaller, more slowly mixing central compartment, so a standard weight-based bolus risks profound hypotension and overdose."},{"text":"Give a larger propofol bolus to overcome the increased volume of distribution of lipophilic drugs in the elderly","label":"B","correct":false,"rationale":"Although increased body fat does raise the volume of distribution and prolong elimination half-life, this calls for a smaller, more slowly titrated dose, not a larger bolus, because the initial distribution and brain sensitivity dominate the induction response."},{"text":"Select pancuronium for maintenance because its long duration reduces the need for redosing in lengthy cases","label":"C","correct":false,"rationale":"Pancuronium is renally eliminated and its action is markedly prolonged in age-related renal impairment, making it a poor choice in this patient."},{"text":"Reduce the propofol induction dose and titrate slowly, and choose cisatracurium for neuromuscular blockade","label":"D","correct":true,"rationale":"Correct — the elderly require lower, slowly titrated induction doses owing to increased CNS sensitivity and slower circulation, and cisatracurium undergoes organ-independent Hofmann elimination, avoiding accumulation despite reduced renal function."},{"text":"Choose rocuronium and plan a fixed redosing schedule identical to that used in young adults","label":"E","correct":false,"rationale":"Aging prolongs the duration of aminosteroid relaxants and slows recovery, so fixed young-adult redosing intervals risk residual paralysis; dosing should instead be guided by quantitative train-of-four monitoring."}]'::jsonb, 'D', 'Aging increases pharmacodynamic sensitivity of the brain to hypnotics and opioids while reducing lean body mass, total body water, hepatic and renal clearance, and increasing body fat. The practical result is that induction agents like propofol should be given in REDUCED doses and titrated slowly, both because of heightened CNS sensitivity and a prolonged circulation time that delays the peak effect. For neuromuscular blockade, cisatracurium is attractive because Hofmann elimination is independent of hepatic and renal function, whereas renally cleared relaxants (pancuronium) and, to a lesser extent, hepatically dependent agents accumulate; quantitative neuromuscular monitoring is essential to avoid residual block.', '{}'::jsonb, 'Subspecialty Care', 'Pharmacology of aging — altered pharmacokinetics/pharmacodynamics and drug selection', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK572137/","source":"Anesthetic Considerations in the Geriatric Population (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Geriatric'),
('authored-batch-r20-045', 'Geriatric', 'An 81-year-old man with long-standing hypertension and preserved ejection-fraction heart failure presents for transurethral resection of a bladder tumor under general anesthesia. Echocardiography shows concentric left ventricular hypertrophy, an ejection fraction of 60%, and grade II diastolic dysfunction. After induction and positioning, his blood pressure falls to 78/52 mmHg and his rhythm converts to atrial fibrillation at 140 beats/min. Which intervention is MOST appropriate given his underlying cardiac physiology?', '[{"text":"Administer a generous afterload-reducing dose of nitroglycerin to lower the elevated systemic pressures","label":"A","correct":false,"rationale":"Aggressive vasodilation drops preload and coronary perfusion pressure in a stiff, preload-dependent ventricle and would worsen the existing hypotension."},{"text":"Give a large dexmedetomidine bolus to slow the heart rate through central sympatholysis","label":"B","correct":false,"rationale":"A dexmedetomidine bolus can cause marked bradycardia and hypotension and is not an appropriate acute treatment for hemodynamically significant tachyarrhythmia in this unstable patient."},{"text":"Start a dobutamine infusion to augment contractility because the problem is systolic pump failure","label":"C","correct":false,"rationale":"The ejection fraction is preserved and the problem is impaired relaxation and lost atrial contribution, so an inotrope adds little and its chronotropy can further shorten diastolic filling."},{"text":"Withhold treatment and permit deliberate hypotension to reduce surgical bleeding","label":"D","correct":false,"rationale":"Permissive hypotension is dangerous in an elderly patient with hypertrophy and diastolic dysfunction who depends on adequate perfusion pressure, and it ignores the destabilizing new tachyarrhythmia."},{"text":"Restore sinus rhythm or control the ventricular rate while maintaining adequate preload and afterload","label":"E","correct":true,"rationale":"Correct — the noncompliant, hypertrophied ventricle depends on the atrial kick and an adequate diastolic filling period, so a rapid loss of sinus rhythm is poorly tolerated and rate/rhythm control plus preserved filling pressures restores output."}]'::jsonb, 'E', 'Aging and chronic hypertension produce a stiff, hypertrophied left ventricle with diastolic dysfunction, which is exquisitely dependent on the atrial contribution to filling (the ''atrial kick'') and on a sufficiently long diastolic period. New-onset atrial fibrillation with a rapid ventricular response removes the atrial kick and shortens diastole, sharply reducing stroke volume and causing hypotension. The correct strategy is to restore sinus rhythm or control the rate while preserving preload and an adequate afterload/coronary perfusion pressure; vasodilators, unnecessary inotropes, and deliberate hypotension all worsen the picture in this preload-dependent, noncompliant ventricle.', '{}'::jsonb, 'Subspecialty Care', 'Cardiovascular physiology of aging — diastolic dysfunction and intraoperative hemodynamics', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK572137/","source":"Anesthetic Considerations in the Geriatric Population (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Geriatric'),
('authored-batch-r20-046', 'Principles & Preop', 'A healthy 28-year-old woman (ASA II for well-controlled asthma) is scheduled for an elective laparoscopic cholecystectomy at 11:00 AM. She is anxious about being hungry and asks the preoperative clinic what she may eat and drink beforehand. She has no history of gastroparesis, reflux, or prior difficult intubation, and her BMI is 24. Following current ASA preoperative fasting recommendations for elective procedures in patients without increased aspiration risk, which instruction is correct?', '[{"text":"She must remain strictly NPO for everything, including water, after midnight","label":"A","correct":false,"rationale":"Incorrect: blanket ''NPO after midnight'' is outdated and leads to unnecessarily prolonged fasting; clear liquids are allowed up to 2 hours before surgery."},{"text":"She may drink milk or a latte with milk up until 2 hours before surgery because dairy is a clear liquid","label":"B","correct":false,"rationale":"Incorrect: milk (other than the small amount in coffee or tea) is treated like a solid/fatty meal and is not a clear liquid, requiring a longer fast."},{"text":"She may eat a fried egg and bacon up until 6 hours before surgery as a light meal","label":"C","correct":false,"rationale":"Incorrect: fried or fatty foods and meat prolong gastric emptying and require an 8-hour fast, not the 6-hour light-meal window."},{"text":"She may have a light meal such as toast up until 6 hours before surgery and clear liquids up until 2 hours before surgery","label":"D","correct":true,"rationale":"Correct: ASA guidance permits a light meal up to 6 hours preoperatively and clear liquids up to 2 hours preoperatively for patients without increased aspiration risk."},{"text":"Because she has asthma, she should fast from all liquids for at least 8 hours to minimize aspiration risk","label":"E","correct":false,"rationale":"Incorrect: well-controlled asthma does not constitute an increased aspiration risk, and prolonging the clear-liquid fast confers no benefit."}]'::jsonb, 'D', 'ASA fasting guidance for elective patients without increased aspiration risk follows the familiar 2-4-6-8 framework: clear liquids up to 2 hours, breast milk up to 4 hours, infant formula/nonhuman milk and a light meal up to 6 hours, and fried/fatty foods or meat up to 8 hours. The 2023 modular update reaffirms clear liquids (which may contain carbohydrate, with or without protein) up to 2 hours and encourages avoiding needlessly prolonged fasting. Milk other than the trace amount in coffee or tea is handled as a solid because its fat content delays gastric emptying.', '{}'::jsonb, 'Subspecialty Care', 'Preoperative fasting guidelines and aspiration risk', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK580524/","source":"Gastric Ultrasound (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Principles & Preop'),
('authored-batch-r20-047', 'Regional & Pain', 'A 92-kg woman undergoes cesarean delivery under spinal anesthesia. For multimodal analgesia the surgical team requests bilateral transversus abdominis plane (TAP) blocks at the end of the case using ropivacaine. The student anesthetist is calculating a safe total dose and counseling the team on monitoring. Which consideration is most important when performing bilateral TAP blocks in this patient?', '[{"text":"TAP blocks deposit anesthetic into a poorly vascularized fascial plane, so systemic absorption is negligible and dose limits can be disregarded","label":"A","correct":false,"rationale":"Incorrect; the TAP is a relatively vascular plane and large volumes are used bilaterally, producing clinically meaningful systemic absorption."},{"text":"Peak plasma concentration occurs immediately at injection, so any toxicity will be apparent before the patient leaves the operating room","label":"B","correct":false,"rationale":"Incorrect; peak plasma levels after TAP block typically occur around 30 minutes after injection, so delayed toxicity can appear after the patient leaves the room."},{"text":"Epinephrine should never be added to the local anesthetic for a TAP block because it has no effect on absorption","label":"C","correct":false,"rationale":"Incorrect; epinephrine can slow systemic absorption and serves as an intravascular marker, so its use is reasonable rather than contraindicated."},{"text":"Pregnancy increases the safe maximum dose of ropivacaine, allowing higher total milligram limits than in non-pregnant adults","label":"D","correct":false,"rationale":"Incorrect; pregnancy does not raise the safe ceiling and parturients have actually shown some of the highest peak plasma levels and symptoms after TAP blocks."},{"text":"Because large volumes are injected into a vascular plane, peak plasma levels can approach or exceed toxic thresholds, so total dose must respect weight-based maximums and patients monitored for LAST","label":"E","correct":true,"rationale":"Correct; bilateral TAP blocks use large local-anesthetic volumes absorbed from a vascular plane, with peak plasma concentrations typically around 30 minutes that may approach toxic ranges, mandating dose calculation and post-block monitoring."}]'::jsonb, 'E', 'The TAP block requires relatively large local-anesthetic volumes, and when performed bilaterally the cumulative dose can be substantial. The neurovascular plane is well perfused, so systemic absorption is significant: peak plasma concentrations generally occur about 30 minutes after injection and have been documented to approach or exceed accepted toxic thresholds, with parturients showing some of the highest levels and symptoms of mild toxicity. Clinicians must calculate total dose against weight-based maximums, consider epinephrine to slow absorption, and monitor for delayed local anesthetic systemic toxicity well beyond the time of injection.', '{}'::jsonb, 'Subspecialty Care', 'Truncal/abdominal wall blocks: TAP block local anesthetic dosing and systemic absorption', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK547730/","source":"Transversus Abdominis Plane Block (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Regional & Pain'),
('authored-batch-r20-048', 'Cardiac', 'A 74-year-old man with a single-chamber transvenous implantable cardioverter-defibrillator (ICD) placed 3 years ago for ischemic cardiomyopathy (EF 30%) presents for an open right hemicolectomy. He has an underlying sinus rhythm at 68/min and is NOT pacemaker-dependent. The surgeon plans to use monopolar electrocautery on the abdomen. A cardiology interrogation the day prior confirmed the device functions normally. The team forgoes reprogramming and instead plans to place a doughnut magnet over the device for the case. Which statement best describes what this magnet will do once it is positioned over the ICD during electrocautery?', '[{"text":"It will suspend antitachycardia therapy (shock and ATP detection) without altering the bradycardia pacing mode","label":"A","correct":true,"rationale":"Correct: in essentially all ICDs the magnet inhibits tachyarrhythmia detection/therapy while leaving the programmed bradycardia pacing mode unchanged, so electrocautery noise cannot trigger an inappropriate shock."},{"text":"It will reprogram the device to asynchronous DOO pacing to prevent oversensing-induced inhibition","label":"B","correct":false,"rationale":"A magnet over an ICD suspends tachytherapy detection but does NOT change the pacing mode to asynchronous, unlike a magnet over a standalone pacemaker."},{"text":"It will both suspend shock delivery and convert any bradycardia pacing to an asynchronous mode","label":"C","correct":false,"rationale":"A magnet suspends tachytherapy in an ICD but has no effect on its bradycardia pacing parameters, so any pacing remains in its programmed demand mode."},{"text":"It will have no effect because ICDs ignore external magnets entirely","label":"D","correct":false,"rationale":"ICDs do respond to magnets by suspending tachytherapy; the response simply differs from the asynchronous-pacing response seen with standalone pacemakers."},{"text":"It will trigger an immediate diagnostic shock to test lead integrity before surgery","label":"E","correct":false,"rationale":"A magnet suspends, rather than triggers, shock therapy; it never delivers a defibrillation as a ''test.''"}]'::jsonb, 'A', 'For a non-pacemaker-dependent patient, a magnet over an ICD is an accepted intraoperative strategy: it suspends tachyarrhythmia detection so electrocautery EMI cannot be misread as VF and provoke an inappropriate shock. Crucially, the magnet does NOT place the ICD into asynchronous bradycardia pacing the way it would for a standalone pacemaker — so a magnet is not protective against EMI-induced pacing inhibition in a pacemaker-dependent ICD patient, who instead needs reprogramming to an asynchronous mode. Knowing the differential magnet response of pacemakers versus ICDs is central to perioperative CIED management.', '{}'::jsonb, 'Subspecialty Care', 'Perioperative management of cardiac implantable electronic devices (ICD magnet response and electromagnetic interference)', 'medium', '[{"url":"https://www.openanesthesia.org/aicds/","source":"Cardiac Implantable Electronic Devices: Internal Cardioverter-Defibrillators (OpenAnesthesia)"}]'::jsonb, 'sme_review', 'Cardiac');
